async function jsonToCsvDataConversion(objArray) {
    // Assuming objArray is always an array of objects
    const array = Array.isArray(objArray) ? objArray : JSON.parse(objArray);
    if (array.length === 0) {
        return ''; // Return empty string if array is empty
    }

    const csvLines = array.map(obj => Object.values(obj).join(',')); // Map each object to CSV line

    return csvLines.join('\r\n');
}

async function downloadCSV(headers, items, fileTitle) {
    if (headers) {
        items.unshift(headers);
    }
    const exportedFileName = fileTitle + '.csv' || 'Crypto Java Results.csv';

    // Convert Object to JSON
    const jsonObject = JSON.stringify(items);
    const csvData = await jsonToCsvDataConversion(jsonObject);

    // Create a temporary download link
    const downloadLink = document.createElement('a');
    downloadLink.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csvData);
    downloadLink.download = exportedFileName;
    downloadLink.target = '_blank';
    downloadLink.click();
}

async function generateRowForDiscovery({ fileType, fileName, filePath, numberOfArtifacts, artefactData, vulnerabilitiesList }) {
    const formatCryptoProperty = (property) => property ? `"${property.replace(/,/g, ';')}"` : ``;

    return {
        fileType: fileType.replace(/,/g, ''),
        fileName,
        filePath,
        numberOfArtifacts,
        artefact: artefactData.title,
        callLine: artefactData.call_line,
        startPosition: artefactData.start,
        endPosition: artefactData.end,
        tooltip: `"${artefactData.tooltip?.join('\n') || ''}"`,
        vulnerabilities: `"${vulnerabilitiesList}"`,
        library: artefactData?.crypto_properties?.library || '',
        primitive: formatCryptoProperty(artefactData?.crypto_properties?.primitive),
        variant: formatCryptoProperty(artefactData?.crypto_properties?.variant),
        oid: formatCryptoProperty(artefactData?.crypto_properties?.oid),
        digestSize: formatCryptoProperty(artefactData?.crypto_properties?.digestSize),
        assetType: formatCryptoProperty(artefactData?.crypto_properties?.assetType),
        cryptoFunction: formatCryptoProperty(artefactData?.crypto_properties?.cryptoFunction),
        isFinal: artefactData?.crypto_properties?.isFinal || '',
        blockSize: artefactData?.crypto_properties?.blockSize !== undefined ? artefactData.crypto_properties.blockSize : '',
        privateKeySize: formatCryptoProperty(artefactData?.crypto_properties?.privateKeySize),
        publicKeySize: formatCryptoProperty(artefactData?.crypto_properties?.publicKeySize),
        mode: formatCryptoProperty(artefactData?.crypto_properties?.mode),
        padding: formatCryptoProperty(artefactData?.crypto_properties?.padding)
    };
}

async function generateRowForAnalysis(historyData) {
    // Define helper functions outside the loop for better performance.
    const safeString = (value, replaceComma = false) => {
        if (!value) { return ''; }
        return replaceComma ? `"${value.replace(/,/g, ';')}"` : `"${value}"`;
    };

    const processProperty = (obj, prop, replaceComma = false) => safeString(obj?.[prop], replaceComma);

    // Process each item in historyData.assets
    const csvRows = historyData?.assets?.map(data => {
        const functionCallsList = (data?.functionCalls || []).map(functionCall => {
            return `Function Call: ${functionCall.functionName}\nFile: ${functionCall.location?.fileName || ''}\n(Line Number: ${functionCall.location?.line || 0}) (Start Column: ${functionCall.location?.startColumn || 0}, End Column: ${functionCall.location?.endColumn || 0})`;
        }).join('\n\n');

        const vulnerabilitiesList = (data?.vulnerabilities || []).map(vulnerability => {
            return `(${vulnerability.vulnerabilityScore.toUpperCase()}) ${vulnerability.debugMessage}`;
        }).join('\n\n');

        return {
            assetID: data.assetId,
            functionCalls: `"${functionCallsList}"`,
            vulnerabilities: `"${vulnerabilitiesList}"`,
            library: data.cryptoProperties?.library || '',
            primitive: processProperty(data.cryptoProperties, 'primitive', true),
            variant: processProperty(data.cryptoProperties, 'variant', true),
            oid: processProperty(data.cryptoProperties, 'oid', true),
            digestSize: processProperty(data.cryptoProperties, 'digestSize', true),
            assetType: processProperty(data.cryptoProperties, 'assetType', true),
            cryptoFunction: processProperty(data.cryptoProperties, 'cryptoFunction', true),
            isFinal: data.cryptoProperties?.isFinal || '',
            blockSize: (data.cryptoProperties?.blockSize || data.cryptoProperties?.blockSize === 0) ? data.cryptoProperties.blockSize : '',
            privateKeySize: processProperty(data.cryptoProperties, 'privateKeySize', true),
            publicKeySize: processProperty(data.cryptoProperties, 'publicKeySize', true),
            mode: processProperty(data.cryptoProperties, 'mode', true),
            padding: processProperty(data.cryptoProperties, 'padding', true)
        };
    });

    return csvRows;
}

// Helper function to format vulnerability type
function formatVulnerabilityType(vulnerability) {
    return vulnerability?.type ? `(Type: ${vulnerability.type})|` : '';
}

// Helper function to format vulnerability score
function formatVulnerabilityScore(vulnerability) {
    return vulnerability.vulnerabilityScore ? vulnerability.vulnerabilityScore.toUpperCase() : '';
}

// Helper function to format the full vulnerability message
function formatVulnerabilityMessage(vulnerability) {
    const typePart = formatVulnerabilityType(vulnerability);
    const scorePart = formatVulnerabilityScore(vulnerability);
    const debugMessage = vulnerability.debugMessage || '';

    return `${typePart} (${scorePart})| ${debugMessage}`;
}

// Main function to generate vulnerabilities list
async function generateVulnerabilitiesList(artefactData) {
    return artefactData?.crypto_vulnerabilities?.map(formatVulnerabilityMessage).join('\n') || '';
}

async function generateDiscoveryResults(data, fileType) {
    const csvRows = [];
    if (data?.results) {
        for (const fileData of data.results) {
            // eslint-disable-next-line @typescript-eslint/naming-convention
            const { name: fileName, full_name: filePath, num_artifacts: numberOfArtifacts, crypto_info = [] } = fileData;

            for (const artefactData of crypto_info) {
                let vulnerabilitiesList = await generateVulnerabilitiesList(artefactData);
                const row = await generateRowForDiscovery({ fileType, fileName, filePath, numberOfArtifacts, artefactData, vulnerabilitiesList });
                csvRows.push(row);
            }
        }
    }
    return csvRows;
}

async function generateInventoryResults(data, fileType) {
    const csvRows = [];
    if (data?.inventory) {
        for (const fileData of data.inventory) {
            // eslint-disable-next-line @typescript-eslint/naming-convention
            const { fileName: filePath, functionName: cryptoFunction, library, line: callLine, startColumn: startPosition, endColumn: endPosition } = fileData;
            const row = { fileType, cryptoFunction, library, filePath, callLine, startPosition, endPosition };
            csvRows.push(row);
        }
    }
    return csvRows;
}

export async function saveToCSVMetaView(data, selectedView) {
    if (selectedView === "results") {
        const headers = {
            fileType: "Language".replace(/,/g, ''),
            fileName: "File Name",
            filePath: "File Path",
            numberOfArtifacts: "No. of Artifacts",
            artefact: "Crypto Artefact Name",
            callLine: "Line Number",
            startPosition: "Start Position",
            endPosition: "End Position",
            tooltip: "Artifact",
            vulnerabilities: "Vulnerabilities",
            library: "Library",
            primitive: "Primitive",
            variant: "Variant",
            oid: "Oid",
            digestSize: "Digest Size",
            assetType: "Asset Type",
            cryptoFunction: "Crypto Function",
            isFinal: "is Final",
            blockSize: "Block Size",
            privateKeySize: "Private Key Size",
            publicKeySize: "Public Key Size",
            mode: "Mode",
            padding: "Padding"
        };

        const fileType = (data?.fileType?.charAt(0).toUpperCase() + data?.fileType?.slice(1)) || '';
        const csvRows = await generateDiscoveryResults(data, fileType);

        if (csvRows.length) {
            const fileTitle = `API discovery results - ${fileType}`;
            downloadCSV(headers, csvRows, fileTitle);
        }
    } else if (selectedView === "inventory") {
        const headers = {
            fileType: "Language".replace(/,/g, ''),
            cryptoFunction: "Crypto Function",
            library: "Library",
            filePath: "File Path",
            callLine: "Line Number",
            startPosition: "Start Position",
            endPosition: "End Position"
        };

        const fileType = (data?.fileType?.charAt(0).toUpperCase() + data?.fileType?.slice(1)) || '';
        const csvRows = await generateInventoryResults(data, fileType);
        
        if (csvRows.length) {
            const fileTitle = `Crypto inventory results - ${fileType}`;
            downloadCSV(headers, csvRows, fileTitle);
        }
    }
}

export async function saveToCSVAdvancedView(historyData) {
    const headers = {
        assetID: "Asset ID",
        functionCalls: "Function Calls",
        vulnerabilities: "Vulnerabilities",
        library: "Library",
        primitive: "Primitive",
        variant: "Variant",
        oid: "Oid",
        digestSize: "Digest Size",
        assetType: "Asset Type",
        cryptoFunction: "Crypto Function",
        isFinal: "is Final",
        blockSize: "Block Size",
        privateKeySize: "Private Key Size",
        publicKeySize: "Public Key Size",
        mode: "Mode",
        padding: "Padding"
    };

    // If historyData is empty, exit early.
    if (!historyData?.assets?.length) { return; }

    const csvRows = await generateRowForAnalysis(historyData);

    // Trigger CSV download if there are any rows.
    const fileTitle = 'Cryptography analysis results';
    downloadCSV(headers, csvRows, fileTitle);
}

async function saveToCSVGraphView(graphData) {

    const headers = {
        fileType: "Language".replace(/,/g, ''),
        linesScanned: "No. of Lines Scanned",
        filesScanned: "No. of Files Scanned",
        methodsScanned: "No. of Methods Scanned",
        cryptoEvidences: "No. of Crypto Evidences",
        quantumStatus: "Quantum Status",
        algorithms: "Algorithms",
        instances: "Instances",
        libraries: "Libraries"
    };

    const csvRows = [];
    const graphContent = graphData?.content || [];
    for (let data of graphContent) {
        const fileType = data?.file_type?.charAt(0).toUpperCase() + data?.file_type?.slice(1) || '';

        csvRows.push(
            {
                fileType: fileType.replace(/,/g, ''),
                linesScanned: data.lines_scanned,
                filesScanned: data.files_scanned,
                methodsScanned: data.methods_scanned,
                cryptoEvidences: data.crypto_evidences,
                quantumStatus: data.quantumStatus.cryptoData.length ? `"${data.quantumStatus.cryptoData.join('\n')}"` : '--',
                algorithms: data.algorithms.cryptoData.length ? `"${data.algorithms.cryptoData.join('\n')}"` : '--',
                instances: data.instances.cryptoData.length ? `"${data.instances.cryptoData.join('\n')}"` : '--',
                libraries: data.libraries.cryptoData.length ? `"${data.libraries.cryptoData.join('\n')}"` : '--'
            }
        );
    }

    if (graphContent.length) {
        const fileTitle = 'dashboard-report';
        downloadCSV(headers, csvRows, fileTitle);
    }
}