export async function loadAdvancedContainer(assetsData, selectedLanguage, loadType) {
	const clonedResult = await cloneDeep(assetsData);
	await saveData(clonedResult, 'clonedResult');

	// handleInventorySwitchVisibility(selectedLanguage);

	const selectedAsset = await getSelectedAsset(assetsData, selectedLanguage, loadType);
	if (!selectedAsset) return handleEmptyAssetSet();

	await saveData(selectedAsset, 'newCrypto');
	await createAdvancedWrapperTemplate();

	if (selectedAsset?.assets?.length) {
		const itemsPerPage = 10;
		const totalPages = Math.ceil(selectedAsset?.assets?.length / itemsPerPage);

		await generatePaginationAssetTemplate(selectedAsset?.assets?.length);
		await renderList('load', selectedAsset?.assets, 1, itemsPerAssetPageGlobal, totalPages);
		await paginationSetupHandler(selectedAsset?.assets || [], loadType);
	} else {
		await handleEmptyAssetSet();
	}
}

function handleInventorySwitchVisibility(selectedLanguage) {
	const metricsWrapper = document.getElementById("matricesWrapper");
	const inventorySwitchWrapper = document.getElementById('inventorySwitch');
	if (selectedLanguage.toLowerCase() === "select") {
		inventorySwitchWrapper.classList.add('hide-flat-switch');
		metricsWrapper.classList.remove("compliance--notification__wrapper");
	} else {
		inventorySwitchWrapper.classList.remove('hide-flat-switch');
		metricsWrapper.classList.add("compliance--notification__wrapper");
	}
}

async function getSelectedAsset(assetsData, selectedLanguage, loadType) {
	if (loadType !== 'filter') {
		const metricsWrapper = document.getElementById("matricesWrapper");
		const selected = assetsData?.find(data => data?.fileType?.toLowerCase() === selectedLanguage?.toLowerCase())?.results?.findings || {};
		await generateMetricsTemplate(selected, 'load');

		metricsWrapper.classList.add("compliance--notification__wrapper");
		return selected;
	} else {
		return assetsData;
	}
}

async function buildAssetsList(selectedAsset, dataToRender) {
	let assetsList = '';
	const labelCounts = {};

	if (selectedAsset?.[0]?.complianceLevels) {
		selectedAsset?.forEach(a => {
			a?.complianceLevels
				.filter(item => item?.type === ComplianceStatus.fipsType)
				.forEach(item => {
					labelCounts[item?.label] = (labelCounts[item?.label] || 0) + 1;
				});
		});
	}

	for (const asset of dataToRender || []) {

		const tooltip = await generateTooltips();
		const properties = await buildPropertiesSection(asset);
		const vulnerabilities = await generateVulnerabilitiesTemplate(asset);
		const vulnerabilityCountText = getVulnerabilityCountText(asset);
		const cryptoAgilityCountText = getCryptoAgilityCountText(asset);
		assetsList += buildAssetAccordion(asset, properties, vulnerabilities, vulnerabilityCountText, cryptoAgilityCountText, tooltip);
	}
	return assetsList || buildNoResultsAccordion();
}

async function buildPropertiesSection(asset) {
	let properties = '';
	const props = asset?.cryptoProperties || {};

	if (Object.keys(props).length) {
		const isFunctionCalls = asset?.functionCalls?.[0]?.location?.fileName;
		if (isFunctionCalls) {
			properties += `
				<tr class="bx--parent-row-v2">
					<td class="bx--table-head-cell">file</td>
					<td class="bx--table-body-cell word-wrap">${isFunctionCalls}
					</td>
				</tr>
			`;
		}

		for (const prop in props) {
			const value = props[prop];
			if (['primitive', 'cryptofunction', 'assettype', 'mode', 'padding'].includes(prop.toLowerCase()) && propertiesContent?.[prop]?.[value]) {
				const tooltip = await getPropertyTooltip(propertiesContent, prop, value);
				properties += `
					<tr class="bx--parent-row-v2">
						<td class="bx--table-head-cell">${prop}</td>
						<td class="bx--table-body-cell tooltip-cell">
							<div>${propertiesContent?.[prop]?.[value]?.name || value}</div>
							${tooltip}
						</td>
					</tr>
				`;
			} else {
				properties += `
					<tr class="bx--parent-row-v2">
						<td class="bx--table-head-cell">${prop}</td>
						<td class="bx--table-body-cell">${value}
						</td>
					</tr>
				`;
			}
		}
	} else {
		properties += `<tr><td>No properties available</td></tr>`;
	}

	return properties;
}

function getVulnerabilityCountText(asset) {
	const count = asset?.vulnerabilities?.length || 0;
	return `${count}`;
}

function getCryptoAgilityCountText(asset) {
	const count = asset?.vulnerabilities.filter(item => item.classification === 'Crypto-agility Anti-pattern')?.length || 0;
	return `${count}`;
}

