async function handleFullAssetLoad(selectedAsset, assetsList, loadType) {
	if (loadType !== 'filter') {
		await saveData(selectedAsset, 'crypto');
		// await createAdvancedWrapperTemplate();

		const filter = await generateFiltersData(selectedAsset);
		await saveData(filter, 'filter');
		await generateGraphs(filter.graphData);
		const vulnerabilitiesCount = await getSavedData('vulnerabilitiesCount');
		const variantsCount = await getSavedData('variantsCount');

		document.getElementById('algoCount').innerText = variantsCount ?? 0;
		document.getElementById('vulCount').innerText = vulnerabilitiesCount ?? 0;
	}

	renderAssetsList(assetsList);
	addUIEventListeners();
	await generateFunctionCallsWrapperTemplate(selectedAsset?.assets || []);
	await loadFilterTemplate('');
	await loadFilterInputTemplate();
	await loadFilterTagsTemplate();
	await addFilterFullData(selectedAsset);
	await tracingEventHandler();

	toggleUIVisibility(selectedAsset.assets?.length > 0);
}

function renderAssetsList(assetsList) {
	document.getElementById('cryptoAssetsWpr').innerHTML = `
		<div class="bx--accordion custom-accordion">
			${assetsList}
		</div>
	`;
}

function addUIEventListeners() {
	document.querySelectorAll('.asset--list__accordion').forEach(item =>
		item.addEventListener('click', () => toggleAccordionContent(item))
	);

	document.querySelectorAll('.expand-fn-icon').forEach(item =>
		item.addEventListener('click', () => handleToggleExpand(item, 'expand'))
	);

	document.querySelectorAll('.expanded-fn-icon').forEach(item =>
		item.addEventListener('click', () => handleToggleExpand(item, 'collapse'))
	);

	document.querySelectorAll('.vulnerabilities--item__header').forEach(item =>
		item.addEventListener('click', () => toggleAccordionContent(item, 'vul', 'advanced'))
	);
}

function toggleUIVisibility(hasAssets) {
	const tooltip = document.querySelector('.tooltip-filter');
	const icons = document.querySelector('.panel-right-icons');
	if (tooltip && icons) {
		tooltip.classList.toggle('hide', !hasAssets);
		icons.classList.toggle('hide', !hasAssets);
	}
}

