// Load Assets List
const generateAssetName = (cryptoProperties, vulnerabilities) => {
	const { cryptoFunction, variant, privateKeySize } = cryptoProperties;

	if (!cryptoProperties || !Object.keys(cryptoProperties).length) {
		return 'Untraceable';
	}

	if (isAntiPatternAsset(cryptoProperties)) {
		return generateAntiPatternAssetName(vulnerabilities);
	}

	return generateAssetTitle(cryptoFunction, variant, privateKeySize);
};

function generateAssetTitle(cryptoFunction, variant, privateKeySize) {

	const partLeft = cryptoFunction || '';
	const partMiddle = variant || '';
	const partRight = privateKeySize ? `${privateKeySize} bit` : '';

	if (partLeft) {
		return `${partLeft} ${partMiddle ? '- (' + partMiddle + ')' : ''} ${partRight ? '- (' + partRight + ')' : ''}`;
	}
	if (partMiddle) {
		return `${partMiddle ? '(' + partMiddle + ')' : ''} ${partRight ? '- (' + partRight + ')' : ''}`;
	}
	if (partRight) {
		return `${partRight ? '(' + partRight + ')' : ''}`;
	}

	return 'Untraceable';
}

// Anti-Pattern (No AssetType and only Library)
const generateAntiPatternAssetName = (vulnerabilities) => {
	if (vulnerabilities && vulnerabilities.length) {
		return vulnerabilities[0]?.classification || '';
	}
	// No Vulnerability
	return 'Untraceable';
};

