async function algorithmLegendGenerator(algorithmData) {
	const modifiedGroupedData = groupByAlgorithm(algorithmData, 'algorithm');

	let algoLegendHtml = `<div class="legend-div">`;
	for (let algorithm of modifiedGroupedData) {
		algoLegendHtml += `<div class="list-div"><div class="legend-item" ><div class="labelBox" style="background:${algorithm.color}"></div> <span>${algorithm.algorithm} (${algorithm.count})</span></div></div>`;

		algoLegendHtml += `<div class="list-div">`;
		for (let keys of algorithm.keys) {
			algoLegendHtml += `<div class="legend-item" ><div class="labelBox" style="background:${keys.color}"></div> <span>${keys.key} ${keys?.key !== 'Unknown' ? '(' + keys.count + ')' : ''}</span></div>`;
		}
		algoLegendHtml += `</div>`;
	}

	algoLegendHtml += `</div>`;
	document.getElementById('algoLegend').innerHTML = algoLegendHtml;
}

async function vulnerabilityLegendGenerator(vulnerabilityData) {
	let legendHtml = `<ul class="legend-list fips-list">`;
	for (let legend of vulnerabilityData.legendData) {
		legendHtml += `<li class="legend-item"><div class="labelBox" style="background:${vulnerabilityData.datasets[0].backgroundColor[legend?.index]}"></div> <span class="vul-legend-text">${legend.label} (${legend.value})</span></li>`;
	}
	legendHtml += `</ul>`;
	const legendElm = document.getElementById('vulLegend');

	if (legendElm) {
		legendElm.innerHTML = legendHtml;
	}
}

async function fipsChartLegend(fipsData) {
	let legendHtml = `<ul class="legend-list fips-list">`;
	for (let legend of fipsData.legendData) {
		legendHtml += `<li class="legend-item"><div class="labelBox" style="background:${fipsData?.datasets?.[0]?.backgroundColor[legend?.index]}"></div> <span class="vul-legend-text">${getFIPSStatus()?.[legend?.label]?.text}</span></li>`;
	}
	legendHtml += `</ul>`;
	const legendElm = document.getElementById('fipsLegend');

	if (legendElm) {
		legendElm.innerHTML = legendHtml;
	}
}

async function graphDataGenerator(graphData) {
	const counts = {};
	graphData.algorithmGraphData.forEach(item => {
		const key = `${item.algorithm}_${item.key}`;

		if (!counts[key]) {
			counts[key] = {
				algorithm: item?.algorithm,
				key: item.key,
				algorithmCount: graphData?.algorithmData?.find(algo => algo.label === item.algorithm)?.value,
				keyCount: 0
			};
		}
		counts[key].keyCount++;
	});

	const algorithmGraphData = Object.values(counts);
	const algorithmCountMap = {};
	algorithmGraphData.forEach(item => {
		const { algorithm, algorithmCount } = item;
		if (!algorithmCountMap[algorithm]) {
			algorithmCountMap[algorithm] = algorithmCount;
		}
	});

	return {
		keyData: algorithmGraphData.sort((a, b) => a.algorithm.toLowerCase() > b.algorithm.toLowerCase() ? 1 : -1),
		algorithmListData: Object.entries(algorithmCountMap).sort().reduce((o, [k, v]) => {
			o[k] = v;
			return o;
		}, {})
	};
}

async function algorithmGraphWrapper(graphData) {
	const { keyData, algorithmListData } = await graphDataGenerator(graphData);
	const algorithmsWithColors = getColors(keyData, 'ALGORITHM');

	const modifiedAlgorithmList = { ...algorithmListData };
	for (const key in algorithmListData) {
		const getColorForAlgo = algorithmsWithColors?.find(item => item.algorithm === key)?.algorithmColor;
		modifiedAlgorithmList[key] = modifiedAlgorithmList[key] + '_' + getColorForAlgo;
	}

	const innerData = algorithmsWithColors.map(key => ({ algorithm: key.algorithm, key: key.key, value: key.keyCount, keyColor: key.key + '_' + key.algorithm }));
	const innerColors = algorithmsWithColors.map(item => item.keyColor);

	const outerData = Array.from(
		d3.rollup(
			innerData,
			v => d3.sum(v, d => d.value),
			d => d.algorithm
		),
		([key, value]) => ({ key, value })
	);
	const outerColors = Object.values(modifiedAlgorithmList).map(item => item.split('_')?.[1]);

	createDonutChart(outerColors, outerData, '#donutChartAlgorithm', innerData, innerColors);
	await algorithmLegendGenerator(algorithmsWithColors);

}

async function vulnerabilitiesGraphWrapper(graphData) {
	const vulnerabilityData = {
		labels: graphData.vulnerabilityLabels,
		legendData: graphData.vulnerabilityData,
		datasets: [{
			data: graphData.vulnerabilityValues,
			backgroundColor: getColors(graphData.vulnerabilityLabels, 'VUL'),
			borderWidth: 0,
			spacing: 2,
			hoverOffset: 10,
			cutout: '90%'
		}],
	};
	const vulChartColors = vulnerabilityData.datasets[0].backgroundColor;
	const vulData = graphData.vulnerabilityData.map(item => ({ key: item.label, value: item.value }));

	// Create Vulnerability donut chart
	createDonutChart(vulChartColors, vulData, '#donutChartVulnerability');
	await vulnerabilityLegendGenerator(vulnerabilityData);
}

async function fipsGraphWrapper(graphData) {
	const fipsDonutData = {
		labels: graphData.fipsLevels,
		legendData: graphData.fipsData,
		datasets: [{
			data: graphData.fipsValues,
			backgroundColor: getColors(graphData.fipsLevels, 'FIPS'),
			borderWidth: 0,
			spacing: 2,
			hoverOffset: 10,
			cutout: '90%'
		}],
	};
	const fipsChartColors = fipsDonutData.datasets[0].backgroundColor;

	const fipsRefinedData = graphData.fipsData.map(item => ({ key: getFIPSStatus()?.[item?.label]?.text, value: item?.value }));

	// Create fips donut chart
	createDonutChart(fipsChartColors, fipsRefinedData, '#donutChartFips');
	await fipsChartLegend(fipsDonutData);
}

export async function generateGraphs(graphData) {

	const parentChartContainerElm = document.getElementById('chartContainer');
	const vulnerabilityChartContainerElm = document.getElementById('vulChartContainer');
	const fipsChartContainerElm = document.getElementById('fipsChartContainer');
	const algorithmChartContainerElm = document.getElementById('algorithmChartContainer');
	const assetContainerElm = document.getElementById('assetContainer');

	algorithmChartContainerElm.classList.remove('hidden');
	vulnerabilityChartContainerElm.classList.remove('hidden');
	parentChartContainerElm.classList.remove('hidden');
	fipsChartContainerElm.classList.remove('hidden');
	assetContainerElm.classList.remove('no-charts');
	await fipsGraphWrapper(graphData);
	await algorithmGraphWrapper(graphData);
	await vulnerabilitiesGraphWrapper(graphData);

	if (!graphData?.vulnerabilitiesCount && !graphData?.variantCount) {
		document.getElementById('algoLegendHeading').classList.add('hide');
		document.getElementById('keyLegendHeading').classList.add('hide');
	}
	else if (!graphData?.variantCount) {
		document.getElementById('algoLegendHeading').classList.add('hide');
		document.getElementById('keyLegendHeading').classList.add('hide');
	}
	else {
		document.getElementById('algoLegendHeading').classList.remove('hide');
		document.getElementById('keyLegendHeading').classList.remove('hide');
	}
}

/**
 * FUNCTION CALLS / PARAMETER TRACING METHODS
 * ------------------------------------------
 **/

async function generateFunctionName(item) {
	return item?.functionName ? item.functionName.split('.').slice(-1).pop() : undefined;
}

async function generateArgumentName(item) {
	if (item?.argumentNode) {
		const variableName = item?.argumentNode?.type === "VALUE" ? item?.argumentNode?.value : item?.argumentNode?.variableName;
		if (item?.argumentNumber === 0) {
			return `<span class="fn-prefix">Called By: </span>` + (variableName || item?.type);
		} else {
			return `<span class="fn-prefix">Parameter ${item?.argumentNumber}: </span>` + (variableName || item?.type);
		}
	} else if (item?.argumentNumber) {
		return `<span class="fn-prefix">Parameter ${item?.argumentNumber}: </span> ${item?.type}`;
	}
	return undefined;
}

async function generateVariableName(item) {
	const variableName = item?.type === "VALUE" ? item?.value : item?.variableName;
	return variableName ? `<span class="fn-prefix">Variable: </span>` + variableName : undefined;
}

async function generateChildTypeNodeName(item) {
	return (item?.type === 'VALUE' ? `<span class="fn-prefix">Value: </span>` + (item.value || item?.type) : item?.type) || item?.type || '';
}

async function generateLocationString(item) {
	if (item?.location) {
		return JSON.stringify(item.location);
	} else if (item?.argumentNode?.location) {
		return JSON.stringify(item.argumentNode.location);
	}
	return '';
}

async function generateTraceBackIcon(isBackTraceButton, assetID) {
	return isBackTraceButton ? `<i class="codicon codicon-debug-step-back trace-back-btn" data-asset="${assetID}"></i>` : ``;
}

function generateArgumentIconTemplate(param, item, assetID, locationStr, argumentIndex, callType) {
	let iconTemplate;
	const variableName = param?.argumentNode?.type === "VALUE" ? param?.argumentNode?.value : param?.argumentNode?.variableName;
	if (param?.argumentNode?.sourceNodes && param?.argumentNode?.sourceNodes.length) {
		iconTemplate = `
		<i class="codicon codicon-diff-added qs--trace__type fn-trace-btn clickable" data-arg="${argumentIndex}" data-node="${param?.argumentNode?.vertexId || 0}" data-function="${item.vertexId}" data-asset="${assetID}" data-location='${locationStr}' data-calltype='${callType}'></i>
		<span class="clickable" data-location='${locationStr}' data-asset="${assetID}">${variableName || param?.type || ''}</span>`;
	} else {
		iconTemplate = `<i class="codicon codicon-circle-slash non-clickable"></i><span class="non-clickable">${variableName || param?.type || ''}</span>`;
	}
	return iconTemplate;
}

async function generateCalledByAndParameters(item, assetID, callType) {
	let calledBy = '';
	let parameters = '';

	if (item?.arguments && item?.arguments.length) {
		item.arguments.forEach(param => {
			const locationStr = param?.argumentNode?.location ? JSON.stringify(param.argumentNode.location) : '';
			const iconTemplate = generateArgumentIconTemplate(param, item, assetID, locationStr, param.argumentNumber, callType);

			if (param?.argumentNumber === 0) {
				calledBy = param?.argumentNode?.variableName === 'unknown'
					? `<span data-node-type="cb" class="called-by-elm item-title cb"></span>`
					: `<span data-node-type="cb" class="called-by-elm item-title cb">${iconTemplate}.</span>`;
			} else {
				parameters += param.argumentNumber === 1
					? `<span data-node-type="pm${param.argumentNumber}" class="called-by-elm item-title pm${param.argumentNumber}">${iconTemplate}</span>`
					: `, <span data-node-type="pm${param.argumentNumber}" class="called-by-elm item-title pm${param.argumentNumber}">${iconTemplate}</span>`;
			}
		});
	}

	return { calledBy, parameters };
}

