function createVariableTraceHTML(item, index, locationString) {
	const isFurtherTrace = !!(item?.sourceNodes?.length || item?.arguments?.length || item?.argumentNode?.sourceNodes?.length);
	const itemVarName = item?.type === "VALUE" ? item?.value : item?.variableName;

	let traceIcon = '';
	if (isFurtherTrace) {
		traceIcon = index === data.length - 1
			? `<i class="codicon codicon-diff-added clickable" data-node="${item?.vertexId || 0}" data-function="${selectedDataSet?.function}" data-asset="${selectedDataSet?.asset}" data-location='${locationString}'></i>
				<span class="item-title clickable" data-location='${locationString}' data-asset="${selectedDataSet.asset}">${itemVarName || ''}</span>`
			: `<i class="codicon codicon-arrow-small-down node-trace-btn"></i>
				<i class="codicon codicon-diff-added clickable" data-node="${item?.vertexId || 0}" data-function="${selectedDataSet?.function}" data-asset="${selectedDataSet?.asset}" data-location='${locationString}'></i>
				<span class="item-title clickable" data-location='${locationString}' data-asset="${selectedDataSet.asset}">${itemVarName || ''}</span>`;
	} else {
		traceIcon = index === data.length - 1
			? `<i class="codicon codicon-circle-slash non-clickable"></i><span class="item-title clickable" data-location='${locationString}' data-asset="${selectedDataSet.asset}">${itemVarName || ''}</span>`
			: `<i class="codicon codicon-arrow-small-down node-trace-btn clickable"></i><span class="item-title clickable" data-location='${locationString}' data-asset="${selectedDataSet.asset}">${itemVarName || ''}</span>`;
	}

	return `
		<span class="var-trace-caret">
			<div class="trace-title-label">${traceIcon}</div>
			<div class="line-number">{${item?.type || ''}: line ${item?.location?.line || 0}}</div>
		</span>`;
}

function addToggleFunctionality(li) {
	li.querySelector('.var-trace-caret').addEventListener('click', function () {
		const nested = this.parentElement.querySelector('.nested');
		const icon = this.querySelector('.codicon');

		if (nested && icon) {
			nested.classList.toggle('active');
			icon.classList.toggle('codicon-diff-added');
			icon.classList.toggle('codicon-diff-removed');
		}
	});
}

/** 
 * Parameter Trace Event Handlers 
 **/

async function tracingEventHandler() {
	document.querySelectorAll('.trace-back-btn').forEach(item => {
		item.removeEventListener('click', handleBackClick);
		item.addEventListener('click', handleBackClick);
	});

	document.querySelectorAll('.qs--trace__type').forEach(item => {
		item.removeEventListener('click', handleFrontClick);
		item.addEventListener('click', handleFrontClick);
	});

	document.querySelectorAll('.qs--variable__trace').forEach(item => {
		item.removeEventListener('click', handleVariableClick);
		item.addEventListener('click', handleVariableClick);
	});
}

function handleBackClick(event) {
	handleBackwardTrace(event.currentTarget);
}

function handleFrontClick(event) {
	handleTraceType(event.currentTarget);
}

function handleVariableClick(event) {
	handleVariableTrace(event.currentTarget);
}

/* Trace Type Handler */
async function handleTraceType(e) {
	if (e.dataset.calltype === "FC") {
		await handleForwardTrace(e);
	} else {
		await handleNestedTrace(e);
	}
}

/* Forward Trace Handler */
async function handleForwardTrace(e) {
	const selectedDataSet = e.dataset;
	const assetID = selectedDataSet.asset;
	const selectedAsset = savedAssetList.filter(elem => elem.assetId === assetID);
	const currentNodeObj = getCurrentNodeData(selectedAsset, selectedDataSet.function);

	await removeSelectedFromAll('selected', assetID);
	// annotateOnEditor(selectedDataSet.location);
	await saveNavigationHistory(selectedDataSet, assetID);

	if (e.classList.contains('codicon-diff-added')) {
		e.closest('.item-title').querySelector('span.clickable').classList.add('selected');
	} else {
		e.closest('.item-title').querySelector('span.clickable').classList.remove('selected');
	}
	await generateNestedTraceTemplate(selectedDataSet, currentNodeObj, 'forward', e);
	await tracingEventHandler();
}

/* Variable Trace Handler */
async function handleVariableTrace(e) {
	const selectedDataSet = e.dataset;
	const assetID = selectedDataSet.asset;
	const selectedAsset = savedAssetList.filter(elem => elem.assetId === assetID);
	const currentNodeObj = getCurrentNodeData(selectedAsset, selectedDataSet.node);

	await removeSelectedFromAll('selected', assetID);
	// annotateOnEditor(selectedDataSet.location);
	await highlightVariableTrace(e);
	await generateVariableTraceTemplate(selectedDataSet, currentNodeObj, e);
}

/* Nested Trace Handler */
async function handleNestedTrace(e) {
	const selectedDataSet = e.dataset;
	const assetID = selectedDataSet.asset;
	const selectedAsset = savedAssetList.filter(elem => elem.assetId === assetID);

	await saveNavigationHistory(selectedDataSet, assetID);

	let currentNodeObj = getCurrentNodeData(selectedAsset, selectedDataSet.function);

	await generateTraceHeaderTemplate(currentNodeObj, assetID, true);

	await toggleHighlightNode(selectedDataSet.arg, assetID, "FN");
	// annotateOnEditor(selectedDataSet.location);
	await generateNestedTraceTemplate(selectedDataSet, currentNodeObj, 'nested');
	await tracingEventHandler();
}

/* Backward Trace Handler */
async function handleBackwardTrace(e) {
	const assetID = e?.dataset?.asset;
	const selectedAsset = savedAssetList.filter(elem => elem.assetId === assetID);

	// Get Trace List
	const getTraceList = await getTraceMemory(assetID);
	const traceIndex = getTraceList && getTraceList.length ? getTraceList.length - 2 : 0;
	const currentTrace = getTraceList && getTraceList.length ? getTraceList[traceIndex] : null;

	if (currentTrace) {
		const dataSet = currentTrace.traceData;
		const currentNodeObj = getCurrentNodeData(selectedAsset, dataSet.function);

		if (traceIndex === 0) {
			await setTraceMemory(dataSet.asset, [currentTrace]);
			await generateTraceHeaderTemplate(currentNodeObj, dataSet.asset, false);
		} else {
			getTraceList.splice(-1);
			await setTraceMemory(dataSet.asset, getTraceList);
			await generateTraceHeaderTemplate(currentNodeObj, dataSet.asset, true);
		}

		await toggleHighlightNode(dataSet.arg, dataSet.asset, "FN");
		// annotateOnEditor(dataSet.location);
		await generateNestedTraceTemplate(dataSet, currentNodeObj, 'backward');
		await tracingEventHandler();
	}
}

