function handleToggleExpand(currentButton, expandType) {
	const assetID = currentButton.dataset.asset;
	const propGrid = document.getElementById(`propGridWrapper-${assetID}`);
	const vulGrid = document.getElementById(`vulGridWrapper-${assetID}`);
	const fnGrid = document.getElementById(`fnGridWrapper-${assetID}`);
	if (expandType === 'collapse') {
		propGrid.classList.remove('hide');
		vulGrid.classList.remove('hide');
		fnGrid.classList.remove('expanded');
		fnGrid.classList.add('collapsed');
		currentButton.closest('.header-tile-content').querySelector('.expand-fn-icon').classList.remove('hide');
		currentButton.classList.add('hide');
		setTimeout(() => {
			fnGrid.classList.remove('collapsed');
		}, 1000);
	} else {
		propGrid.classList.add('hide');
		vulGrid.classList.add('hide');
		fnGrid.classList.remove('collapsed');
		fnGrid.classList.add('expanded');
		fnGrid.classList.add('animate-expanded');
		currentButton.closest('.header-tile-content').querySelector('.expanded-fn-icon').classList.remove('hide');
		currentButton.classList.add('hide');
		setTimeout(() => {
			fnGrid.classList.remove('animate-expanded');
		}, 1000);
	}
}

async function saveNavigationHistory(selectedDataSet, assetID) {
	const getTraceList = await getTraceMemory(assetID);
	const traceIndex = getTraceList?.findIndex(elm => elm.traceData.function === selectedDataSet.function);
	const isFnAleradyPresent = getTraceList && getTraceList.length && traceIndex !== -1;

	if (!isFnAleradyPresent) {
		if (selectedDataSet && Object.keys(selectedDataSet).length) {
			getTraceList.push({ 'trace': getTraceList.length, 'traceData': selectedDataSet });
			await setTraceMemory(assetID, getTraceList);
		}
	} else {
		getTraceList[traceIndex] = { 'trace': getTraceList.length, 'traceData': selectedDataSet };
		await setTraceMemory(assetID, getTraceList);
	}
}

async function getTraceMemory(assetID) {
	return JSON.parse(localStorage.getItem(`functionsNavigationHistory-${assetID}`)) || [];
}

async function setTraceMemory(assetID, data) {
	const setData = data ? JSON.stringify(data) : null;
	localStorage.setItem(`functionsNavigationHistory-${assetID}`, setData);
}

function getCurrentNodeData(obj, value, completeObj) {
	if (obj === value) {
		return completeObj;
	} else if (typeof obj !== "object" || obj === null) {
		return false;
	} else {
		for (const key in obj) {
			const getCurrentNode = getCurrentNodeData(obj[key], value, obj);
			if (getCurrentNode) {
				return getCurrentNode;
			}
		}
		return false;
	}
}

async function toggleHighlightNode(argument, assetID, traceType) {
	const selectedFunctionCallWrapper = document.getElementById(`functionCallsWrappepr-${assetID}`);

	if (traceType === 'FN') {
		// 	// function-call-head-title
		const functionCallHeaderWrapper = selectedFunctionCallWrapper.querySelector('.function-call-head-title');
		if (argument === 0 || argument === "0") {

			functionCallHeaderWrapper.querySelector('.item-title.cb').querySelector('span.clickable').classList.add('selected');
			functionCallHeaderWrapper.querySelector('.item-title.cb').querySelector('.codicon').classList.toggle('codicon-diff-added');
			functionCallHeaderWrapper.querySelector('.item-title.cb').querySelector('.codicon').classList.toggle('codicon-diff-removed');
		} else {

			functionCallHeaderWrapper.querySelector(`.item-title.pm${argument}`).querySelector('span.clickable').classList.add('selected');
			functionCallHeaderWrapper.querySelector(`.item-title.pm${argument}`).querySelector('.codicon').classList.toggle('codicon-diff-added');
			functionCallHeaderWrapper.querySelector(`.item-title.pm${argument}`).querySelector('.codicon').classList.toggle('codicon-diff-removed');
		}
	}
}

function highlightReference(e) {
	if (e && e.stopPropagation) {
		e.stopPropagation();
	};
	[...e.closest(".vul-reference-list").querySelectorAll('.vul-reference-link')].forEach(sib => sib.classList.remove('selected'));
	e.classList.add('selected');

	const locationString = e.dataset.location;
	annotateOnEditor(locationString);
}

async function highlightTrace(e) {
	if (e && e.stopPropagation) {
		e.stopPropagation();
	};

	await removeSelectedFromAll('selected', e.dataset.asset);


	if (e.closest('.item-title') && e.closest('.item-title').querySelector('span.clickable')) {
		e.closest('.item-title').querySelector('span.clickable').classList.toggle('selected');
	} else if (e.querySelector('span.clickable')) {
		e.querySelector('span.clickable').classList.toggle('selected');
	} else {
		e.classList.toggle('selected');
	}

	const locationString = e.dataset.location;
	annotateOnEditor(locationString);
}

async function highlightVariableTrace(e) {
	const variableTraceWrapper = e.closest('.trace-list-item').querySelector('.variable-trace-wrapper');

	if (e.classList.contains('codicon-diff-removed')) {
		variableTraceWrapper.classList.add('hide');
	} else {
		variableTraceWrapper.classList.remove('hide');
	}

	if (e.classList.contains('codicon-diff-added')) {
		e.classList.remove('codicon-diff-added');
		e.classList.add('codicon-diff-removed');
		e.closest('.trace-title-label').querySelector('span.clickable').classList.add('selected');
	} else if (e.classList.contains('codicon-diff-removed')) {
		e.classList.remove('codicon-diff-removed');
		e.classList.add('codicon-diff-added');
		e.closest('.trace-title-label').querySelector('span.clickable').classList.remove('selected');
	}
}

async function resetOpenIcon(assetID) {
	const selectedFunctionCallWrapper = document.getElementById(`functionCallsWrappepr-${assetID}`);
	const elms = selectedFunctionCallWrapper.querySelectorAll('.function-call-head-title .codicon-diff-removed');
	const addClassName = 'codicon-diff-added';
	const removeClassName = 'codicon-diff-removed';

	elms.forEach(elm => {
		elm.classList.remove(removeClassName);
		elm.classList.add(addClassName);
	});
}

async function removeSelectedFromAll(className, assetID) {
	const selectedFunctionCallWrapper = document.getElementById(`functionCallsWrappepr-${assetID}`);
	const elms = selectedFunctionCallWrapper.querySelectorAll('span.clickable');

	elms.forEach(elm => {
		if (elm.classList.contains(className)) {
			elm.classList.remove(className);
		}

		// Check nested span elements
		const nestedElms = elm.querySelectorAll('span.clickable');
		nestedElms.forEach(nestedElm => {
			if (nestedElm.classList.contains(className)) {
				nestedElm.classList.remove(className);
			}
		});
	});
}

