function handleChangeAssetPagination(e) {
	const itemPerPageValue = document.getElementById("itemsPerPageAsset");
	const currentPageValue = document.getElementById("current-page-asset");
	updateAndRenderList(Number(currentPageValue.value), Number(itemPerPageValue.value));
}

async function updateAndRenderList(modifiedCurrentPage, itemPerPage) {
	const resultWithoutFilters = await getSavedData('resultWithoutFilters');
	const resultWithFilters = await getSavedData('filteredData');
	await filterList(resultWithFilters ?? resultWithoutFilters, modifiedCurrentPage, itemPerPage);
}

// Filter Handler
async function filterList(fullResultData, currentPage, itemsPerPage) {
	const result = fullResultData.filter(item => item !== null);
	const totalPages = Math.ceil(result.length / itemsPerPage) || 1;

	if (currentPage > totalPages) {
		currentPage = 1;
	}

	await renderList('filter', result, currentPage, itemsPerPage, totalPages);
}

async function paginationSetupHandler(assetsList, loadType) {
	const resultWithoutFilters = await getSavedData('resultWithoutFilters') || assetsList;
	const itemsPerPage = 10;
	const totalPages = Math.ceil(assetsList?.length / itemsPerPage);
	await saveData(assetsList, 'resultWithoutFilters');
	const findingWrapperElm = document.getElementById('cryptoAssetsWpr');
	findingWrapperElm.classList.remove("hide");
	findingWrapperElm.classList.add("show");

	if (loadType === 'filter') {
		await renderList(loadType, resultWithoutFilters, 1, itemsPerAssetPageGlobal, totalPages);
	}
	await paginationAssetEventsHandler();
}

// Pagination events handler (i.e. Next and Previous)
async function paginationAssetEventsHandler() {
	// Event listeners for pagination buttons
	document.getElementById('prevBtn').addEventListener('click', function () {
		if (currentAssetPageGlobal > 1) {
			currentAssetPageGlobal--;
			updateAndRenderList(currentAssetPageGlobal, itemsPerAssetPageGlobal);
		}
	});

	document.getElementById('nextBtn').addEventListener('click', function () {
		if (currentAssetPageGlobal < totalAssetPagesGlobal) {
			currentAssetPageGlobal++;
			updateAndRenderList(currentAssetPageGlobal, itemsPerAssetPageGlobal);
		}
	});
}

export async function renderList(loadType = 'load', selectedAsset, currentPage, itemsPerPage, totalPages) {

	itemsPerAssetPageGlobal = itemsPerPage;
	totalAssetPagesGlobal = totalPages;
	currentAssetPageGlobal = currentPage;

	const currentPageText = document.getElementById("current-page-asset");
	const currentItemsText = document.getElementById("current-items-asset");
	const totalPagesText = document.getElementById("total-pages-asset");
	const totalItemsText = document.getElementById("total-items-asset");
	const itemsPerPageDropdown = document.getElementById("itemsPerPageAsset");
	const prevButton = document.getElementById('prevBtn');
	const nextButton = document.getElementById('nextBtn');

	const startIndex = (currentPage - 1) * itemsPerPage;
	const endIndex = Math.min(startIndex + itemsPerPage, selectedAsset?.length);
	const dataToRender = selectedAsset?.slice(startIndex, endIndex);

	const fullAssetData = await getSavedData('newCrypto');
	const assetsList = await buildAssetsList(fullAssetData?.assets, dataToRender);

	await handleFullAssetLoad(fullAssetData, assetsList, loadType);

	let pagesDropdownList = '';
	for (let i = 0; i < totalPages; i++) {
		pagesDropdownList += `<option class="bx--select-option" value="${i + 1}">${i + 1}</option>`;
	}
	currentPageText.innerHTML = pagesDropdownList;

	// Update page number
	currentPageText.value = currentPage || 1;
	totalPagesText.textContent = totalPages || 1;
	totalItemsText.textContent = selectedAsset?.length || 0;

	// Enable/Disable prev and next buttons
	prevButton.disabled = currentPage === 1;
	nextButton.disabled = currentPage === totalPages;

	function calculateItemsOnPage(itemsPerPage, totalItems, currentPage) {
		let startIndex = (currentPage - 1) * itemsPerPage + 1;
		let endIndex = Math.min(currentPage * itemsPerPage, totalItems);

		return `${startIndex}-${endIndex}`;
	}

	currentItemsText.textContent = calculateItemsOnPage(itemsPerPage, selectedAsset?.length, currentPage);
	itemsPerPageDropdown.value = itemsPerPage;
}