async function themeSwitcherEvents() {
  const themeSwitch = document.getElementById('theme-toggle');
  if (!themeSwitch) return;

  const body = document.body;
  const savedTheme = localStorage.getItem('qs-carbon-theme');
  const isDark = !savedTheme || savedTheme === 'vscode-dark';

  // Set initial theme
  const initialTheme = isDark ? 'vscode-dark' : 'vscode-light';
  body.className = initialTheme;
  body.setAttribute('theme', initialTheme);
  themeSwitch.checked = isDark;

  // Handle theme toggle
  themeSwitch.addEventListener('change', (e) => {
    const newTheme = e.target.checked ? 'vscode-dark' : 'vscode-light';
    body.className = newTheme;
    body.setAttribute('theme', newTheme);
    localStorage.setItem('qs-carbon-theme', newTheme);
  });
}

