async function initialFileSystemEvents() {
  const fileSystemView = document.getElementById('fileSystemView');
  const uploadInput = document.getElementById('uploadInput');
  const selectFolderBtn = document.getElementById('selectFolderBtn');
  const selectedFolderPath = document.getElementById('selectedFolderPath');

  selectFolderBtn.addEventListener('click', () => {
    uploadInput.click();
  });

  uploadInput.addEventListener('change', async (event) => {
    allFiles = [];
    const files = event.target.files;

    if (files.length === 0) {
      console.log("No directory or files selected.");
      return;
    }

    let rootDirName = '';
    if (files?.[0]?.webkitRelativePath) { // Set Selected Root Directory
      const firstPathPart = files[0].webkitRelativePath.split('/')[0];
      if (firstPathPart) {
        rootDirName = firstPathPart;
        selectedFolderPath.classList.remove('hide');
        selectedFolderPath.textContent = `${rootDirName}/`;
      }
    }

    const fileTree = await generateFilesTree(files);
    await handleFileSystemVisibility();

    renderFileSystem(fileTree, fileSystemView);
    event.target.value = '';
  });
}

async function generateFilesTree(files) {
  const fileTree = {};

  for (const file of [...files]) {
    if (await validateResultFile(file)) {
      allFiles.push(file);

      const pathParts = file.webkitRelativePath.split('/').filter(part => part !== '');

      pathParts.reduce((acc, part, index) => {
        if (!acc[part]) {
          acc[part] = index === pathParts.length - 1
            ? { __file: file.webkitRelativePath }
            : {};
        }
        return acc[part];
      }, fileTree);
    }
  };

  return fileTree;
}

function renderFileSystem(data, parentElement) {
  parentElement.innerHTML = '';

  const ul = createFileSystemList(data);
  parentElement.appendChild(ul);
}

async function handleFileSystemVisibility() {
  const resultFilesWrapper = document.getElementById('resultFilesWrapper');
  const noResultsWrapper = document.getElementById("noResultsWrapper");
  const resultsWrapper = document.getElementById("resultsWrapper");

  resultFilesWrapper.classList.remove('hide');
  resultsWrapper.classList.add('hide');
  noResultsWrapper.classList.remove('hide');
}

function isDirectory(item) {
  return typeof item === 'object' && !item?.__file && item !== null && !Array.isArray(item);
}

function createFileSystemList(data) {
  const ul = document.createElement('ul');
  ul.classList.add('header-list-wrapper');

  const sortedKeys = sortKeysByTypeAndName(data);

  for (const key of sortedKeys) {

    const li = createFileSystemItem(key, data[key]);
    if (li) ul.appendChild(li);
  }

  if (sortedKeys && !sortedKeys.length) {
    ul.textContent = 'No crypto result found.'
  }

  return ul;
}

function sortKeysByTypeAndName(data) {
  return Object.keys(data).sort((a, b) => {
    const isADir = isDirectory(data[a]);
    const isBDir = isDirectory(data[b]);

    if (isADir !== isBDir) return isADir ? -1 : 1;
    return a.localeCompare(b);
  });
}

function createFileSystemItem(key, value) {
  const li = document.createElement('li');

  if (isDirectory(value)) {
    if (IGNORED_DIRECTORIES.includes(key)) return null;
    appendDirectoryContent(li, key, value);
  } else {
    appendFileContent(li, key, value);
  }

  return li;
}

function appendDirectoryContent(li, key, value) {
  const span = document.createElement('span');
  span.classList.add('directory');
  span.innerHTML = `<i class="codicon codicon-folder"></i> <span title="${key}">${key}/</span>`;
  li.appendChild(span);

  const nestedUl = createFileSystemList(value);
  nestedUl.classList.add('hidden');
  li.appendChild(nestedUl);

  span.addEventListener('click', () => {
    nestedUl.classList.toggle('hidden');
  });
}

function appendFileContent(li, key, value) {
  const span = document.createElement('span');
  span.classList.add('file');
  span.innerHTML = `<i class="codicon codicon-symbol-file"></i> <span title="${key}">${key}</span>`;
  li.classList.add('file-list-item');
  li.dataset.index = value?.__file;
  li.appendChild(span);

  li.addEventListener('click', handleFileClick);
}

async function handleFileClick(e) {
  const li = e.currentTarget;
  const fileIndex = li.dataset.index;
  const selectedFile = allFiles.find(file => file.webkitRelativePath === fileIndex);

  await saveData({ filePath: fileIndex, file: selectedFile }, 'file');

  if (!selectedFile) return;

  const noResultsWrapper = document.getElementById("noResultsWrapper");
  const loaderElement = document.getElementById('loader');

  document.querySelectorAll('.files-list-wrapper li.file-list-item')
    .forEach(file => file.classList.remove('selected'));

  noResultsWrapper.classList.add('hide');
  loaderElement.classList.remove('hide');
  li.classList.add('selected');

  const siblingFiles = await getFilesFromSameDirectory(allFiles, selectedFile);
  displayFileContent({ file: selectedFile, directory: siblingFiles });
}

async function displayFileContent(file) {
  if (file?.file?.type === 'application/json') {
    try {
      await loadDataToView(file);
    } catch (error) {
      console.error(`Error - ${error.message}`);
    }
  }
}

async function validateResultFile(file) {
  const startsWithValidPrefix =
    file.name.startsWith('quantum_safe_cryptography_analysis') ||
    file.name.startsWith('quantum_safe_api_discovery');

  const fileTypeJSON =
    startsWithValidPrefix &&
    !file.name.includes('cbom') &&
    !file.name.includes('issue_summary') &&
    file.type === 'application/json';

  return !!fileTypeJSON;
}

function removeUnwantedDirectories(arr, values) {
  if (!Array.isArray(values)) {
    values = [values];
  }

  const index = arr.findIndex(item => values.includes(item));
  if (index === -1) {
    return [...arr];
  }
  return arr.slice(0, index);
}

async function getFilesFromSameDirectory(files, referenceFile) {
  const refDir = referenceFile.webkitRelativePath.substring(0, referenceFile.webkitRelativePath.lastIndexOf("/"));
  return files.filter(file =>
    file.webkitRelativePath.startsWith(refDir + "/") &&
    file.webkitRelativePath.split("/").length === referenceFile.webkitRelativePath.split("/").length
  );
}
