/**
 * Method is used to hide the tooltip.
 * 
 * Parameters =>
 * -------------
 * event: current event,
 * element: DOM Element set to be hidden
 **/
export function hideTooltip(event, element) {
    let tooltip = element.closest('.tooltip');
    tooltip.classList.remove('active');
    event.stopPropagation();
}

export function handleKeyPress(event, element) {
    if (event.keyCode === 13) {
        event.preventDefault();
        hideTooltip(event, element);
    }
}

/**
 * Method is used to toggle the Asset & Vulnerabilities Accordion.
 * 
 * Parameters =>
 * -------------
 * accordionItem: DOM Element set to be active/hidden
 * data: DataSet to trigger the highlight event
 **/
export function toggleAccordionContent(accordionItem, type, langType) {
    accordionItem.classList.toggle('bg-header-accordion');
    const svg = accordionItem.querySelector('.bx--icon');
    if (svg) {
        svg.classList.toggle('arrow-rotate');
    }
    hideOtherAccordionContent(accordionItem.parentNode);
    const content = accordionItem.nextElementSibling;
    content.classList.toggle('custom-accordion__content--visible');

    /* if (accordionItem.classList.contains('bg-header-accordion') && type === 'vul') {
        const locationString = accordionItem.dataset.location;
        if (langType && langType === 'standard') {
            const parsedLocation = JSON.parse(locationString);
            highlightFile(parsedLocation, 'standard');
        } else {
            annotateOnEditor(locationString);
        }
    } */

    function hideOtherAccordionContent(elem) {
        let sibling = elem.parentNode.firstChild;
        while (sibling) {
            if (sibling.nodeType === 1 && sibling !== elem) {
                sibling.querySelector('.custom-accordion__content').classList.remove('custom-accordion__content--visible');
                sibling.querySelector('.custom-accordion__heading').classList.remove('bg-header-accordion');
                sibling.querySelector('.bx--icon').classList.remove('arrow-rotate');
            }
            sibling = sibling.nextSibling;
        }
    };
}

export function toggleExportTooltip(element) {
    const content = element.nextElementSibling;
    content.classList.toggle('bx--content__visible');
}


/**
 * Method is used to group the array of objects to array of list.
 * 
 * Parameters =>
 * -------------
 * xs: Array of objects generated from filter generation 
 *      i.e. [{"value":"DES","checked":false},{"value":"DES","checked":false}],
 * key: Property to filter the data from array of objects
 **/

export function groupBy(xs, key) {
    const groupData = xs.reduce(function (rv, x) {
        const groupKey = x[key];
        if (rv[groupKey]) {
            rv[groupKey].push(x); // Push the entire object `x` into the array
        } else {
            rv[groupKey] = [x]; // Initialize a new array with `x` as the first element
        }
        return rv; // Always return the accumulator `rv` after modification
    }, {});

    // Transform groupData into the required format
    return Object.keys(groupData).map((key, index) => {
        return { label: key, value: groupData[key].length, index: index };
    });
}

export function groupByAlgorithm(xs, key) {
    const groupData = xs.reduce((rv, x) => {
        const groupKey = x[key];
        if (!rv[groupKey]) {
            rv[groupKey] = { items: [], algorithmColor: x.algorithmColor, algorithmCount: x.algorithmCount };
        }
        rv[groupKey].items.push(x);
        return rv;
    }, {});

    return Object.keys(groupData).map((groupKey, index) => {
        const group = groupData[groupKey];
        return {
            algorithm: groupKey,
            color: group.algorithmColor,
            count: group.algorithmCount,
            keys: groupByKey(group.items, 'key', 'keyColor')
        };
    });
}

export function groupByKey(xs, key, secondKey) {
    const groupData = xs.reduce((rv, x) => {
        const groupKey = x[key];
        if (!rv[groupKey]) {
            rv[groupKey] = { items: [], keyColor: x.keyColor, keyCount: x.keyCount };
        }
        rv[groupKey].items.push(x);
        return rv;
    }, {});

    return Object.keys(groupData).map((groupKey) => {
        const group = groupData[groupKey];
        return {
            key: groupKey,
            color: group.keyColor,
            count: group.keyCount
        };
    });
}

export function generateJavaGraphData(arr = []) {
    const itemCountMap = arr.reduce((map, item) => {
        map.set(item, (map.get(item) || 0) + 1);
        return map;
    }, new Map());

    const cryptoGraphData = Object.fromEntries(itemCountMap);
    return {
        cryptoLabels: Object.keys(cryptoGraphData),
        cryptoValue: Object.values(cryptoGraphData),
        cryptoData: Object.entries(cryptoGraphData).map(([key, value]) => `${key} (${value})`)
    };
}


/**
 * Method is used to get a color pallet based on the data count to show the graph.
 * 
 * Parameters =>
 * -------------
 * length: Length will be the count of data values,
 * type: Pallet types - P1 is when we need to use 1st Pallet and P2 is when we need to use second pallet.
 **/
export function getColors(data, type) {
    let colors = [];

    // Get all color palettes upfront
    const colorPalettes = {
        red: getColorPallet('red', 'primary'),
        magenta: getColorPallet('magenta', 'primary'),
        blue: getColorPallet('blue', 'primary'),
        purple: getColorPallet('purple', 'primary'),
        cyan: getColorPallet('cyan', 'primary'),
        teal: getColorPallet('teal', 'primary'),
    };

    if (type === 'ALGORITHM') {
        // Get unique algorithms
        const uniqueAlgorithms = [...new Set(data.map(item => item.algorithm))];
        const algoColors = getColorPallet('algo', 'primary', uniqueAlgorithms.length);

        // Map algorithms to colors
        const algorithmsSet = uniqueAlgorithms.map((item, index) => ({
            algorithm: item,
            color: algoColors[index].color,
            shade: algoColors[index].shade,
            weight: algoColors[index].weight
        }));

        const currentColor = { blue: 0, purple: 0, magenta: 0 };
        const selectedAlgorithms = new Set();

        // Map data with colors
        colors = data.map((item) => {
            const selectedAlgorithm = algorithmsSet.find(algo => algo.algorithm === item.algorithm);
            if (!selectedAlgorithm) { return item; }  // Guard clause in case of missing algorithm

            // Determine color adjustments
            if (!selectedAlgorithms.has(selectedAlgorithm.algorithm)) {
                currentColor[selectedAlgorithm.shade] = Number(selectedAlgorithm.weight) - 10;
                selectedAlgorithms.add(selectedAlgorithm.algorithm);
            } else {
                currentColor[selectedAlgorithm.shade] -= 10;
            }

            const selectedColorPallet = getColorPallet(selectedAlgorithm.shade, 'full');
            const iteratedKeyColors = `${selectedAlgorithm.shade}${currentColor[selectedAlgorithm.shade]}`;

            return {
                ...item,
                colorTheme: selectedAlgorithm.shade,
                algorithmColor: selectedAlgorithm.color,
                keyColor: selectedColorPallet[iteratedKeyColors],
            };
        });

    } else if (type === 'VUL') {
        // Define vulnerability color mapping upfront
        const vulnerabilitiesColors = {
            critical: colorPalettes.red.red50,
            high: colorPalettes.red.red40,
            medium: colorPalettes.red.red30,
            low: colorPalettes.purple.purple40,
            info: colorPalettes.blue.blue50,
            none: colorPalettes.teal.teal40,
            unknown: colorPalettes.magenta.magenta40,
        };

        // Map data to vulnerability colors
        colors = data.map((item) => vulnerabilitiesColors[item.toLowerCase()] || vulnerabilitiesColors.unknown);

    } else if (type === 'FIPS') {
        // Define vulnerability color mapping upfront
        const fipsColors = {
            fips1403L1Compliant: colorPalettes.blue.blue50,
            fips1403L1Capable: colorPalettes.purple.purple40,
            fips1403L1NonCompliant: colorPalettes.red.red50,
            unknown: colorPalettes.purple.purple20,
            notApplicable: colorPalettes.teal.teal50,
            fips1403L1Swappable: colorPalettes.cyan.cyan50
        };
        // Map data to vulnerability colors
        colors = data.map((item) => fipsColors[item] || fipsColors.unknown);

    } else {
        // Combined palette for standard language doughnut charts
        const combinedPallet = [
            ...Object.values(colorPalettes.blue),
            ...Object.values(colorPalettes.purple),
            ...Object.values(colorPalettes.magenta),
            ...Object.values(colorPalettes.cyan),
            ...Object.values(colorPalettes.red),
            ...Object.values(colorPalettes.teal)
        ];

        // Shuffle the palette and assign colors
        const modifiedPallet = shuffleArray(combinedPallet);
        colors = data?.map((_, index) => modifiedPallet[index % modifiedPallet.length]);
    }

    return colors;
}

export function getColorPallet(color, type, algoCount) {
    const colorsPallet = {
        blue: {
            'blue10': '#edf5ff', 'blue20': '#d0e2ff', 'blue30': '#a6c8ff', 'blue40': '#78a9ff',
            'blue50': '#4589ff', 'blue60': '#0f62fe', 'blue70': '#0043ce', 'blue80': '#002d9c',
            'blue90': '#001d6c', 'blue100': '#001141'
        },
        cyan: {
            'cyan10': '#e5f6ff', 'cyan20': '#bae6ff', 'cyan30': '#82cfff', 'cyan40': '#33b1ff',
            'cyan50': '#1192e8', 'cyan60': '#0072c3', 'cyan70': '#00539a', 'cyan80': '#003a6d',
            'cyan90': '#012749', 'cyan100': '#061727'
        },
        purple: {
            'purple10': '#f6f2ff', 'purple20': '#e8daff', 'purple30': '#d4bbff', 'purple40': '#be95ff',
            'purple50': '#a56eff', 'purple60': '#8a3ffc', 'purple70': '#6929c4', 'purple80': '#491d8b',
            'purple90': '#31135e', 'purple100': '#1c0f30'
        },
        teal: {
            'teal10': '#d9fbfb', 'teal20': '#9ef0f0', 'teal30': '#3ddbd9', 'teal40': '#08bdba',
            'teal50': '#009d9a', 'teal60': '#007d79', 'teal70': '#005d5d', 'teal80': '#004144',
            'teal90': '#022b30', 'teal100': '#081a1c'
        },
        red: {
            'red10': '#fff1f1', 'red20': '#ffd7d9', 'red30': '#ffb3b8', 'red40': '#ff8389',
            'red50': '#fa4d56', 'red60': '#da1e28', 'red70': '#a2191f', 'red80': '#750e13',
            'red90': '#520408', 'red100': '#2d0709'
        },
        magenta: {
            'magenta10': '#fff0f7', 'magenta20': '#ffd6e8', 'magenta30': '#ffafd2', 'magenta40': '#ff7eb6',
            'magenta50': '#ee5396', 'magenta60': '#d02670', 'magenta70': '#9f1853', 'magenta80': '#740937',
            'magenta90': '#510224', 'magenta100': '#2a0a18'
        }
    };

    /** 
   * Primary Color Pallet
   * ----------------------
   * */

    const primaryColors = {
        blue: {
            'blue60': colorsPallet.blue.blue60,
            'blue50': colorsPallet.blue.blue50,
            'blue40': colorsPallet.blue.blue40,
            'blue30': colorsPallet.blue.blue30,
            'blue20': colorsPallet.blue.blue20
        },
        purple: {
            'purple60': colorsPallet.purple.purple60,
            'purple50': colorsPallet.purple.purple50,
            'purple40': colorsPallet.purple.purple40,
            'purple30': colorsPallet.purple.purple30,
            'purple20': colorsPallet.purple.purple20

        },
        magenta: {
            'magenta60': colorsPallet.magenta.magenta60,
            'magenta50': colorsPallet.magenta.magenta50,
            'magenta40': colorsPallet.magenta.magenta40,
            'magenta30': colorsPallet.magenta.magenta30,
            'magenta20': colorsPallet.magenta.magenta20
        },
        cyan: {
            'cyan60': colorsPallet.cyan.cyan60,
            'cyan50': colorsPallet.cyan.cyan50,
            'cyan40': colorsPallet.cyan.cyan40,
            'cyan30': colorsPallet.cyan.cyan30,
            'cyan20': colorsPallet.cyan.cyan20
        },
        teal: {
            'teal60': colorsPallet.teal.teal60,
            'teal50': colorsPallet.teal.teal50,
            'teal40': colorsPallet.teal.teal40,
            'teal30': colorsPallet.teal.teal30,
            'teal20': colorsPallet.teal.teal20
        },
        red: {
            'red60': colorsPallet.red.red60,
            'red50': colorsPallet.red.red50,
            'red40': colorsPallet.red.red40,
            'red30': colorsPallet.red.red30,
            'red20': colorsPallet.red.red20
        }
    };

    if (color === 'all') { return primaryColors; };

    if (color === 'algo') {
        const algorithmColorSet = [];
        const colorKeys = ['blue', 'purple', 'magenta'];
        const initialValues = { blue: 60, purple: 50, magenta: 50 };

        const pushColors = (shade, weight) => {
            algorithmColorSet.push({ color: colorsPallet[shade][`${shade}${weight}`], shade, weight });
        };

        let currentColor = { ...initialValues };
        const algorithmGroupLength = Math.ceil(algoCount / 3);

        for (let i = 0; i <= algorithmGroupLength; i++) {
            colorKeys.forEach((colorKey) => {
                const currentShade = currentColor[colorKey];
                const newShade = currentShade + 10;
                pushColors(colorKey, newShade === 110 ? initialValues[colorKey] : newShade);
                currentColor[colorKey] = newShade === 110 ? initialValues[colorKey] : newShade;
            });
        }

        return algorithmColorSet;
    }

    return type === 'full' ? colorsPallet[color] : primaryColors[color];
}

export function shuffleArray(array) {
    for (let i = array.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [array[i], array[j]] = [array[j], array[i]];  // Swap using array destructuring
    }
    return array;
}

