export function handleOutsideClick(button, dropdownListWrapper) {

    // button                 - Dropdown Button
    // dropdownListWrapper    - List Wrapper

    document.addEventListener('click', function (event) {
        const isClickInside = button?.contains(event.target) || dropdownListWrapper?.contains(event.target);
        if (!isClickInside) {
            dropdownListWrapper?.classList.remove('bx--content__visible');
            // button.setAttribute('aria-expanded', false);
            // dropdownListWrapper.setAttribute('aria-hidden', true);
        }
    });
}