export function getAdvancedLanguageList(loadedData) {

    const advancedResultsLanguages = (loadedData?.crypto?.advancedResults || [])
        .map(lang => lang.fileType) ?? [];
    const standardResultsLanguages = (loadedData?.crypto?.standardResults || [])
        .map(lang => lang.fileType) ?? [];
    const allLanguages = [...new Set([...advancedResultsLanguages, ...standardResultsLanguages])];

    return allLanguages
        ?.filter(item => loadedData?.crypto?.config?.advancedLanguages?.includes(item)) || [];
}

export function getStandardLanguageList(loadedData) {
    return (loadedData?.crypto?.standardResults || [])
        .filter(lang => lang.fileType.toLowerCase() !== 'java')
        .map(lang => lang.fileType);
}

export function processData(loadedData) {
    let advancedData = null;
    let standardData = null;
    let showAdvanced = loadedData?.crypto?.config?.showAdvancedData || false;
    let showStandard = loadedData?.crypto?.config?.showStandardData || false;
    let selectedFile = loadedData?.crypto?.selectedFile ?? null;

    if (showAdvanced) {
        advancedData = loadedData?.crypto?.advancedResults || [];
    }

    if (showStandard && loadedData?.crypto?.standardResults?.length) {
        standardData = loadedData?.crypto?.standardResults || null;
    }

    return { advancedData, standardData, showAdvanced, showStandard, selectedFile };
}

export async function handleFileScan(loadedData, standardLanguageList, advancedLanguageList, advancedData, standardData) {
    const dropdownSelected = document.getElementById('dropdownSelected');
    if (loadedData?.crypto?.config?.isFileScan && loadedData?.crypto?.config?.scanFileExtension?.toLowerCase() !== 'all') {
        const initialLanguage = standardLanguageList?.[0] || 'Select';
        dropdownSelected.textContent = initialLanguage + '*';

        if (advancedLanguageList.includes(loadedData?.crypto?.config?.scanFileExtension?.toLowerCase())) {
            await loadAdvancedContainer(advancedData, loadedData?.crypto?.config?.scanFileExtension?.toLowerCase(), 'load');
        } else {
            await loadStandardContainer(standardData, initialLanguage, advancedLanguageList, loadedData?.crypto?.config, 'load');
        }
    }
}

export async function handleDataDisplay(loadedData, advancedLanguageList, standardLanguageList, advancedData, standardData, selectedFile) {
    const dropdownSelected = document.getElementById('dropdownSelected');
    const config = loadedData?.crypto?.config;

    if (config?.isFileScan && config?.scanFileExtension?.toLowerCase() !== 'all') {
        await handleFileScanDataDisplay(config, advancedLanguageList, standardLanguageList, advancedData, standardData, dropdownSelected);
    } else if (config?.showAdvancedData || config?.isAdvancedFilter === 'advanced' || config?.isAdvancedFilter === 'combined') {
        await handleAdvancedOrStandardDisplay(config, advancedLanguageList, standardLanguageList, advancedData, standardData, dropdownSelected);
    } else if (config?.showStandardData) {
        await handleStandardDataDisplay(standardLanguageList, standardData, config, dropdownSelected);
    } else {
        await handleDefaultDisplay(advancedLanguageList, advancedData, dropdownSelected);
    }
}

export async function handleErrorMessage() {
    const dropdownSelected = document.getElementById('dropdownSelected');
    dropdownSelected.textContent = 'Select';
    await loadAdvancedContainer(null, 'Select', 'load');
}

export async function handleLanguageDropdownEvents(
    {
        advancedData,
        standardData,
        showAdvanced,
        showStandard,
        advancedLanguageList,
        standardLanguageList,
        config
    }
) {

    const languageDropdownElm = document.getElementById('languageSelect');
    const dropdown = document.getElementById('dropdown');
    const dropdownSelected = document.getElementById('dropdownSelected');
    const dropdownList = dropdown.nextElementSibling;

    const elements = { languageDropdownElm, dropdown, dropdownSelected, dropdownList };
    const processingData = { advancedData, standardData, showAdvanced, showStandard, advancedLanguageList, standardLanguageList, config };

    await dropdownClickEventHandler(elements, processingData);
    await dropdownListClickEventHandler(elements, processingData);
    await dropdownOutsideClickEventHandler(elements);
    await inventorySwitchEventHandler(processingData);
};

