export async function inventorySwitchHandler(advancedData, standardData, advancedLanguageList, standardLanguageList, config, eventType) {

    const dropdownSelected = document.getElementById('dropdownSelected');
    const analysisSwitchElm = document.getElementById('analysisBtn');
    const inventorySwitchElm = document.getElementById('inventoryBtn');
    const inventorySwitchWrapper = document.getElementById('inventorySwitch');
    const metricsWrapper = document.getElementById('matricesWrapper');
    let isJavaInventory = -1;
    if (standardData) {
        isJavaInventory = standardData.findIndex(item => item?.fileType === 'java');
    }

    if (config?.showAdvancedData || config?.showStandardData) {

        if (!config?.showAdvancedData && isJavaInventory !== -1) {
            analysisSwitchElm.setAttribute('aria-selected', 'false');
            inventorySwitchElm.setAttribute('aria-selected', 'true');
            inventorySwitchWrapper.classList.add('disable-flat-switch');

            dropdownSelected.textContent = "java";
            await loadStandardContainer(standardData, "java", advancedLanguageList, config, 'load');
        } else if (isJavaInventory === -1) {
            inventorySwitchElm.setAttribute('aria-selected', 'false');
            analysisSwitchElm.setAttribute('aria-selected', 'true');
            inventorySwitchWrapper.classList.add('disable-flat-switch');
        }
    } else {
        metricsWrapper.classList.remove('compliance--notification__wrapper');
        inventorySwitchWrapper.classList.add('hide-flat-switch');
    }
}

async function getResultFileSourceName(checkScannedLanguagesType, selectedFile, isInventory, isMetricsData) {
    const selectedFileType = await checkSelectedFileType(selectedFile?.file);
    const isStandard = checkScannedLanguagesType === ScannedLanguages.standard;

    if (isStandard) {
        if (selectedFileType === 'analysis') return false;

        if (isMetricsData) {
            return FilesAndFolders.reportStandard;
        } else if (isInventory) {
            return FilesAndFolders.resultFlatInventory;
        } else {
            return FilesAndFolders.resultStandard;
        }
    } else {
        if (selectedFileType === 'discovery') return false;

        if (await validateAnalysisFineName(selectedFile?.file)) {
            return selectedFile?.file?.name;
        }
        return false;
    }
}

export async function getHistory(checkScannedLanguagesType, selectedFile, isInventory = false, isMetricsData = false) {
    return new Promise((resolve) => {
        setTimeout(async () => {

            const isJSON = (str) => {
                try {
                    JSON.parse(str);
                    return true;
                } catch (e) {
                    return false;
                }
            };

            const reader = new FileReader();
            const fileType = await getResultFileSourceName(checkScannedLanguagesType, selectedFile, isInventory, isMetricsData);

            if (!fileType) {
                resolve(null);
            }

            const file = selectedFile.directory.find(item => item.name === fileType);
            if (file) {

                reader.readAsText(file);
                reader.onload = (e) => {
                    if (file.type === 'application/json') {
                        try {
                            const jsonContent = isJSON(e?.target?.result) ? JSON.parse(e.target.result) : null;
                            if (checkScannedLanguagesType === ScannedLanguages.advanced) {
                                resolve([{
                                    fileType: 'java',
                                    results: jsonContent
                                }]);
                            } else {
                                resolve(jsonContent);
                            }
                        } catch (error) {
                            console.error(`Error - ${error.message}`);
                            resolve(null);
                        }
                    }
                };

                reader.onerror = () => {
                    console.error(`Error reading file: ${reader.error.name}`);
                    resolve(null);
                };
            } else {
                resolve(null);
            }
        }, 1000);
    });
}

export async function loadDataToView(file) {

    try {
        const loadedData = { crypto: await seedDataToWebview(file) };
        localStorage.clear();

        const resultsWrapper = document.getElementById("resultsWrapper");
        const loaderElement = document.getElementById('loader');
        loaderElement.classList.add('hide');
        resultsWrapper.classList.remove('hide');

        let advancedLanguageList = getAdvancedLanguageList(loadedData);
        let standardLanguageList = getStandardLanguageList(loadedData);

        await generateMetricsTemplate([], 'load');

        let { advancedData, standardData, showAdvanced, showStandard, selectedFile } = processData(loadedData);

        await generateLanguageListTemplate('load');
        await handleLanguageDropdownEvents(
            {
                advancedData,
                standardData,
                showAdvanced,
                showStandard,
                advancedLanguageList,
                standardLanguageList,
                config: loadedData?.crypto?.config
            }
        );

        await handleFileScan(loadedData, standardLanguageList, advancedLanguageList, advancedData, standardData);
        await handleDataDisplay(loadedData, advancedLanguageList, standardLanguageList, advancedData, standardData, selectedFile);

        await inventorySwitchHandler(advancedData, standardData, advancedLanguageList, standardLanguageList, loadedData?.crypto?.config, 'load');
        removeAllAccordions();
    } catch (error) {
        console.error('Error handling message event:', error);
        // await handleErrorMessage();
    }
}

async function seedDataToWebview(selectedFile) {

    let webviewData = {
        advancedResults: 'null',
        standardResults: 'null',
        selectedFile: { file: selectedFile?.file },
        config: {
            advancedLanguages: ADVANCED_LANGUAGES,
            advancedExtensions: ADVANCED_EXTENSIONS,
            relativePathExtensions: RELATIVE_PATH_EXTENSIONS,
            supportedFileExtensions: SUPPORTED_FILE_EXTENSIONS,
            languageMultiExtensions: LANGUAGE_EXTENSIONS,
            nonInventoryExtensions: NON_INVENTORY_EXTENSIONS,
            sourceFilter: ['.java', '.cpp'],
            isFileScan: false,
            scanFileExtension: null,
            isAdvancedFilter: true,
            showAdvancedData: false,
            showStandardData: false

        }
    };

    try {
        const [advancedHistoryData, standardHistoryData, flatInventoryHistoryData, standardMetricsData] = await Promise.allSettled(
            [
                getHistory(ScannedLanguages.advanced, selectedFile, false, false),
                getHistory(ScannedLanguages.standard, selectedFile, false, false),
                getHistory(ScannedLanguages.standard, selectedFile, true, false),
                getHistory(ScannedLanguages.standard, selectedFile, false, true)
            ]
        );

        //Graph
        let standardResults = [];
        const standardPromiseData = standardHistoryData?.status === "fulfilled" ? standardHistoryData?.value : 'null';
        const standardInventoryData = flatInventoryHistoryData?.status === "fulfilled" ? flatInventoryHistoryData?.value : { findings: [] };
        const standardReportData = standardMetricsData?.status === "fulfilled" ? standardMetricsData?.value : 'null';
        let standardGraphData = await getGraphData(standardReportData) ?? {};

        if (standardPromiseData?.children) {
            standardResults = standardPromiseData?.children?.map((item) => {
                const fileType = item.file_type;
                return {
                    fileType: fileType,
                    results: item?.children,
                    matrics: standardGraphData?.content?.find((a) => a?.file_type === fileType) || null,
                    inventory: standardInventoryData?.findings?.find((a) => a?.fileType === fileType)?.children || []
                };
            }) || [];
        } else if (standardInventoryData?.findings) {
            standardResults = standardInventoryData?.findings?.map((item) => {
                const fileType = item.fileType;
                return {
                    fileType: fileType,
                    results: standardPromiseData?.children?.find((a) => a?.file_type === fileType) || null,
                    matrics: standardGraphData?.content?.find((a) => a?.file_type === fileType) || null,
                    inventory: item?.children
                };
            }) || [];
        }
        else if (standardReportData?.children) {
            standardResults = standardReportData?.children?.map((item) => {
                const fileType = item.file_type;
                return {
                    fileType: fileType,
                    results: standardPromiseData?.children?.find((a) => a?.file_type === fileType) || null,
                    matrics: standardGraphData?.content?.find((a) => a?.file_type === fileType) || null,
                    inventory: standardInventoryData?.findings?.find((a) => a?.fileType === fileType)?.children || []
                };
            }) || [];
        }

        const javaMetrics = standardGraphData?.content?.find((a) => a?.file_type?.toLowerCase() === 'java') || null;
        const javaInventory = standardInventoryData?.findings?.find((a) => a?.fileType === 'java')?.children || [];
        if (javaMetrics?.files_scanned) {
            standardResults.unshift({
                fileType: 'java',
                results: null,
                matrics: javaMetrics,
                inventory: javaInventory
            });
        }

        webviewData.config.showAdvancedData = !!(advancedHistoryData?.status === "fulfilled" && advancedHistoryData?.value);
        webviewData.config.showStandardData = !!standardResults.length;
        webviewData.advancedResults = advancedHistoryData?.status === "fulfilled" ? advancedHistoryData?.value : 'null';
        webviewData.standardResults = standardResults ?? null;
        return webviewData;

    } catch (error) {
        console.log(`Load Data Error: - ${error.message}`);
        return webviewData;
    }
}

async function checkSelectedFileType(file) {
    if (file) {
        return file.name.startsWith('quantum_safe_api_discovery_') ? 'discovery' : 'analysis';
    }
    return null;
}

async function validateAnalysisFineName(file) {
    if (file) {
        return !!file.name.startsWith('quantum_safe_cryptography_analysis_findings');
    }
    return null;
}

async function handleFileScanDataDisplay(config, advancedLanguageList, standardLanguageList, advancedData, standardData, dropdownSelected) {
    const initialLanguage = standardLanguageList?.[0] || 'Select';
    dropdownSelected.textContent = initialLanguage + '*';

    if (advancedLanguageList.indexOf(config?.scanFileExtension?.toLowerCase()) !== -1) {
        await loadAdvancedContainer(advancedData, config?.scanFileExtension?.toLowerCase(), 'load');
    } else {
        await loadStandardContainer(standardData, initialLanguage, advancedLanguageList, config, 'load');
    }
}

async function handleAdvancedOrStandardDisplay(config, advancedLanguageList, standardLanguageList, advancedData, standardData, dropdownSelected) {
    let isJavaInventory = -1;
    if (standardData && standardData.length) {
        isJavaInventory = standardData.findIndex(item => item?.fileType === 'java');
    }

    if (!config?.showAdvancedData && isJavaInventory !== -1) {
        dropdownSelected.textContent = (advancedLanguageList?.[0] || 'Select');
        await loadStandardContainer(standardData, standardLanguageList?.[0] || 'Select', advancedLanguageList, config, 'load');
    } else if (config?.showStandardData && !config?.showAdvancedData) {
        dropdownSelected.textContent = (standardLanguageList?.[0] || 'Select') + '*';
        await loadStandardContainer(standardData, standardLanguageList?.[0] || 'Select', advancedLanguageList, config, 'load');
    } else if (!config?.showStandardData && !config?.showAdvancedData) {
        dropdownSelected.textContent = 'Select';
        await loadAdvancedContainer(advancedData, advancedLanguageList?.[0] || 'Select', 'load');
    } else {
        dropdownSelected.textContent = (advancedLanguageList?.[0] || 'Select');
        await loadAdvancedContainer(advancedData, advancedLanguageList?.[0] || 'Select', 'load');
    }
}

async function handleStandardDataDisplay(standardLanguageList, standardData, config, dropdownSelected) {
    dropdownSelected.textContent = (standardLanguageList?.[0] || 'Select') + '*';
    await loadStandardContainer(standardData, standardLanguageList?.[0] || 'Select', [], config, 'load');
}

async function handleDefaultDisplay(advancedLanguageList, advancedData, dropdownSelected) {
    dropdownSelected.textContent = 'Select';
    await loadAdvancedContainer(advancedData, advancedLanguageList?.[0] || 'Select', 'load');
}

// Function to toggle the dropdown open/close state
async function toggleDropdownVisibility({ languageDropdownElm, dropdown, dropdownList }) {
    const expanded = dropdown.getAttribute('aria-expanded') === 'true' || false;
    if (!expanded) {
        languageDropdownElm.classList.add('bx--dropdown--open');
    } else {
        languageDropdownElm.classList.remove('bx--dropdown--open');
    }
    dropdown.setAttribute('aria-expanded', !expanded);
    dropdownList.setAttribute('aria-hidden', expanded);
}

// Function to sort the language list alphabetically
function sortLanguageList(languageList) {
    return languageList.sort((a, b) => a.localeCompare(b, undefined, { sensitivity: "base" }));
}

// Function to create a language dropdown button
function createLanguageButton(language, selectedLang, isSelected = false, isAdvanced = false) {
    const langName = language.charAt(0).toUpperCase() + language.slice(1);
    const selectedClass = isSelected ? 'selected-lang' : '';
    const suffix = isAdvanced ? '' : '*';
    return `<button role="dropdown-item" aria-label="${langName} menu item" class="bx--dropdown-item ${selectedClass}" role="button" tabindex="0" value="${language}">${langName}${suffix}</button>`;
}

// Function to generate advanced language list buttons
async function generateAdvancedLanguageButtons({ advancedLanguageList, dropdownSelected }) {
    let languageDropdownList = '';
    const sortedAdvancedList = sortLanguageList(advancedLanguageList);

    sortedAdvancedList.forEach(language => {
        const isSelected = language.toLowerCase() === dropdownSelected.textContent.toLowerCase();
        languageDropdownList += createLanguageButton(language, dropdownSelected.textContent, isSelected, true);
    });

    return languageDropdownList;
}

// Function to generate standard language list buttons
async function generateStandardLanguageButtons({ standardLanguageList, advancedLanguageList, dropdownSelected }) {
    let languageDropdownList = '';
    const sortedStandardList = sortLanguageList(standardLanguageList);

    sortedStandardList.forEach(language => {
        if (advancedLanguageList.indexOf(language.toLowerCase()) === -1) {
            const isSelected = (language.toLowerCase() + '*') === dropdownSelected.textContent.toLowerCase();
            languageDropdownList += createLanguageButton(language, dropdownSelected.textContent, isSelected);
        }
    });

    return languageDropdownList;
}

// Handle Dropdown Click
async function dropdownClickEventHandler({ languageDropdownElm, dropdown, dropdownSelected, dropdownList },
    { advancedData, standardData, showAdvanced, showStandard, advancedLanguageList, standardLanguageList, config }) {
    dropdown.addEventListener('click', async function () {
        let languageDropdownList = '';

        // Toggle dropdown visibility
        await toggleDropdownVisibility({ languageDropdownElm, dropdown, dropdownList });

        let isJavaInventory = -1;
        if (standardData) {
            isJavaInventory = standardData.findIndex(item => item?.fileType === 'java');
        }
        if (showAdvanced || isJavaInventory !== -1) {
            languageDropdownList += await generateAdvancedLanguageButtons({ advancedLanguageList, dropdownSelected });
        }

        if (showStandard && standardLanguageList.length) {
            languageDropdownList += await generateStandardLanguageButtons({ standardLanguageList, advancedLanguageList, dropdownSelected });
        }

        document.getElementById('dropdownList').innerHTML = `${languageDropdownList}`;
    });
}

// Handle Dropdown List Click
async function dropdownListClickEventHandler({ languageDropdownElm, dropdown, dropdownSelected, dropdownList },
    { advancedData, standardData, showAdvanced, showStandard, advancedLanguageList, standardLanguageList, config }) {
    const inventorySwitchWrapper = document.getElementById('inventorySwitch');
    dropdownList.addEventListener('click', async function (event) {
        if (event.target.classList.contains('bx--dropdown-item')) {
            dropdownSelected.textContent = event.target.textContent;
            dropdown.setAttribute('aria-expanded', 'false');
            dropdownList.setAttribute('aria-hidden', false);
            languageDropdownElm.classList.remove('bx--dropdown--open');

            const selectedLang = event.target.getAttribute('value');
            if (advancedLanguageList.indexOf(selectedLang) !== -1) {
                inventorySwitchWrapper.classList.remove('hide-flat-switch');
                await loadAdvancedContainer(advancedData, selectedLang, 'load');

                const analysisSwitchElm = document.getElementById('analysisBtn');
                const inventorySwitchElm = document.getElementById('inventoryBtn');
                inventorySwitchElm.setAttribute('aria-selected', 'false');
                analysisSwitchElm.setAttribute('aria-selected', 'true');

                await inventorySwitchHandler(advancedData, standardData, advancedLanguageList, standardLanguageList, config, 'click');
            } else {
                inventorySwitchWrapper.classList.add('hide-flat-switch');
                await loadStandardContainer(standardData, selectedLang, advancedLanguageList, config, 'load');
            }
        }
    });
}

// Handle Dropdown Outside Click
async function dropdownOutsideClickEventHandler({ languageDropdownElm, dropdown, dropdownSelected, dropdownList }) {
    document.addEventListener('click', function (event) {
        const isClickInside = dropdown.contains(event.target) || dropdownList.contains(event.target);
        if (!isClickInside) {
            languageDropdownElm.classList.remove('bx--dropdown--open');
            dropdown.setAttribute('aria-expanded', false);
            dropdownList.setAttribute('aria-hidden', true);
        }
    });
}

// Loop through buttons and add event listeners
async function inventorySwitchEventHandler({ advancedData, standardData, showAdvanced, showStandard, advancedLanguageList, standardLanguageList, config }) {
    // Select all the content switcher buttons and panels
    const switchWrapper = document.getElementById('inventorySwitch');
    const buttons = document.querySelectorAll('.bx--content-switcher-btn__label');
    const panels = document.querySelectorAll('.bx--content-switcher__panel');
    const metricsWrapper = document.getElementById('matricesWrapper');

    buttons.forEach(button => {
        button.addEventListener('click', async () => {
            if (switchWrapper.classList.contains('disable-flat-switch')) {
                return false;
            }

            // Remove active state from all buttons
            buttons.forEach(b => b.setAttribute('aria-selected', 'false'));

            // Hide all panels
            panels.forEach(panel => panel.setAttribute('hidden', true));

            // Set the clicked button as active
            button.setAttribute('aria-selected', 'true');

            const selectedLang = document.getElementById('dropdownSelected').textContent.toLowerCase().split("*")?.[0];
            if (button.dataset.panel === "discovery") {
                metricsWrapper.classList.remove('compliance--notification__wrapper');
                await loadStandardContainer(standardData, selectedLang, advancedLanguageList, config, 'load');
            } else {
                metricsWrapper.classList.add('compliance--notification__wrapper');
                await loadAdvancedContainer(advancedData, selectedLang, 'load');
            }
        });
    });
}