function handleTabClick(type) {
    const suggestiveChevron = document.getElementById('sugChevron');
    const vulnerabilityChevron = document.getElementById('vulChevron');
    const suggestiveListWrapper = document.getElementById('suggestiveListWrapper');
    const vulnerabilityListWrapper = document.getElementById('vulnerabilityListWrapper');

    if (type === 'suggestive') {
        suggestiveChevron.classList.toggle('rotate-right');
        suggestiveListWrapper.classList.toggle('hide');
    } else if (type === 'vulnerability') {
        vulnerabilityChevron.classList.toggle('rotate-right');
        vulnerabilityListWrapper.classList.toggle('hide');
    } else if (type === 'expandAll') {
        suggestiveChevron.classList.remove('rotate-right');
        vulnerabilityChevron.classList.remove('rotate-right');

        suggestiveListWrapper.classList.remove('hide');
        vulnerabilityListWrapper.classList.remove('hide');
    } else if (type === 'collapseAll') {
        suggestiveChevron.classList.add('rotate-right');
        vulnerabilityChevron.classList.add('rotate-right');

        suggestiveListWrapper.classList.add('hide');
        vulnerabilityListWrapper.classList.add('hide');
    }
}

function callStandardCsvMethod() {
    const exportButtonDiscovery = document.getElementById('exportButtonDiscovery');

    saveToCSVMetaView(csvFullData || [], currentView);
    exportButtonDiscovery?.nextElementSibling?.classList.remove('bx--content__visible');
}

async function tabTrigger() {
    const tab = Tab; // Import the Tab component
    const tabsContainers = document.querySelectorAll('[data-tabs]'); // Find all tab containers

    tabsContainers?.forEach(container => {
        if (tab) {
            tab.create(container); // Initialize each tab component
        }
    });

    await discoveryTabsHandler();
}

async function discoveryTabsHandler() {
    const tabs = document.querySelectorAll('.bx--tabs__nav-item');

    // Handle the tab switch
    tabs.forEach(link => {
        link.addEventListener('click', function (event) {
            event.preventDefault(); // Prevent the default anchor link behavior

            if (event?.target?.dataset?.tab === "inventory") {
                currentView = "inventory";
                document.getElementById('algoCount').innerText = inventoryArtifactsCount ?? 0;
            } else {
                currentView = "results";
                document.getElementById('algoCount').innerText = resultsArtifactsCount ?? 0;
            }
        });
    });
}

