async function treeClickEvent(event) {
    const allElements = document.querySelectorAll('.artefact-title');
    allElements.forEach(el => el.classList.remove('highlight-item'));
    event.target.classList.add('highlight-item');
    const selectedArtefact = event.target.dataset;
    const uaid = selectedArtefact.uaid.split('_*');
    const decodedUAID = {
        title: uaid?.[0] || '',
        primitive: uaid?.[1] || '',
        function: uaid?.[2] || '',
        line: uaid?.[3] || 0,
        start: uaid?.[4] || 0,
        end: uaid?.[5] || 0
    };

    let getSelectedArtefact;
    if (decodedUAID?.primitive) {
        getSelectedArtefact = standardFullData
            ?.find((b) => b.file_id === selectedArtefact.fileid).crypto_info
            ?.find((c) => {
                const primitiveParam = c?.crypto_properties?.primitive || '';
                const functionParam = c?.crypto_properties?.cryptoFunction || '';
                return c.title === selectedArtefact.artefact && primitiveParam === decodedUAID?.primitive && functionParam === decodedUAID?.function && Number(c.call_line) === Number(decodedUAID?.line) && Number(c.start) === Number(decodedUAID?.start);
            });

    } else if (decodedUAID?.function) {
        getSelectedArtefact = standardFullData
            ?.find((b) => b.file_id === selectedArtefact.fileid).crypto_info
            ?.find((c) => c.title === selectedArtefact.artefact && c?.crypto_properties?.cryptoFunction === decodedUAID?.function && Number(c.call_line) === Number(decodedUAID?.line) && Number(c.start) === Number(decodedUAID?.start));

    } else {
        getSelectedArtefact = standardFullData
            ?.find((b) => b.file_id === selectedArtefact.fileid).crypto_info
            ?.find((c) => c.title === selectedArtefact.artefact && Number(c.call_line) === Number(decodedUAID?.line) && Number(c.start) === Number(decodedUAID?.start));

    }

    await loadMetaData(JSON.stringify(getSelectedArtefact));
}

async function createTree() {
    let toggler = document.getElementsByClassName("caret");
    let i;

    for (i = 0; i < toggler.length; i++) {
        toggler[i].addEventListener("click", function () {
            this.parentElement.querySelector(".nested").classList.toggle("active");
            this.classList.toggle("caret-down");
        });
    }
}

function searchArtifacts(event, dataset) {
    const searchInput = event.value.length >= 2 ? event.value : '';

    let filteredResults = [];
    filteredResults = _.cloneDeep(standardFullData);

    let filteredChildren = filteredResults?.filter(child => {
        return child?.name?.toLowerCase().includes(searchInput?.toLowerCase()) || searchInput === '';
    });


    if (filteredResults.length > 0) {
        filteredResults.splice(0, filteredResults.length);
    }

    filteredResults.push(...filteredChildren);

    loadTreeView(filteredResults, dataset.language?.toLowerCase());
    document.querySelector('.artifectNode').classList.toggle("caret-down");
    document.getElementById('artifectlist').classList.add('active');
    document.getElementById('searchArticfects').value = event.value;
    document.getElementById('metaView').innerHTML = '';
    document.getElementById('additionalTitle').innerHTML = '';
    document.getElementById('vulnerabilitiesList').innerHTML = '';
    document.getElementById('suggestiveList').innerHTML = '';
    document.getElementById('treeWrapper').classList.remove('hide');
    document.getElementById('searchArticfects').focus();

}

async function loadTreeView(results, languageChildName) {
    const treeWrapper = document.getElementById('treeWrapper');
    treeWrapper.innerHTML = '';

    const childrenArr = results?.length ? results : [];
    const languageChildCount = childrenArr.reduce((total, fileChildResults) => total + (fileChildResults?.crypto_info?.length || 0), 0);

    const languageChildList = buildLanguageChildList(languageChildName, languageChildCount, childrenArr);
    const parentList = `<li><ul style="padding-left:0px">${languageChildList}</ul></li>`;

    treeWrapper.insertAdjacentHTML('beforeend', parentList);
    toggleVisibilityBasedOnResults(results);

    await treeEventHandlers();
    await createTree();
}

async function treeEventHandlers() {
    const searchInput = document.getElementById('searchArticfects');
    const searchClearButton = document.getElementById('clearInputFilterBtnDiscovery');

    searchInput?.addEventListener('keyup', function (e) {
        searchArtifacts(e.target, e.target.dataset)
    });

    searchClearButton?.addEventListener('click', function (e) {
        searchArtifacts(searchClearButton, searchClearButton.dataset)
    });

    document.querySelectorAll('.artefact-title-button').forEach((singleArtifact) => {
        singleArtifact.addEventListener('click', function (e) {
            treeClickEvent(e);
        })
    });
}

function buildLanguageChildList(languageChildName, languageChildCount, childrenArr) {
    let fileChildList = '';

    childrenArr.forEach(fileChildResults => {
        const fileChildName = fileChildResults?.name || '';
        const fileChildFullName = fileChildResults?.full_name || '';
        const fileChildId = fileChildResults?.file_id || '';
        const fileChildCount = fileChildResults?.crypto_info?.length || 0;

        const artefactList = buildArtefactList(fileChildResults?.crypto_info || [], languageChildName, fileChildName, fileChildFullName, fileChildId);

        fileChildList += `
            <li>
                <button class="caret" style="padding-left:24px;" tabindex="0" role="button" aria-label="${fileChildName} (${fileChildCount})">
                    <svg alt="chevron arrow" class="caret-disc" width="14" height="14" viewBox="0 0 14 14" fill="currentColor" class="bx--icon qs-list-closed" xmlns="http://www.w3.org/2000/svg">
                        <rect width="14" height="14" fill="white" fill-opacity="0.01" style="mix-blend-mode:multiply"/>
                        <path d="M8 11L3 6.00005L3.7 5.30005L8 9.60005L12.3 5.30005L13 6.00005L8 11Z"/>
                    </svg>
                    <div class="standard-file-title">${fileChildName} (${fileChildCount})</div>
                </button>
                <div style="padding-left:0px" class="nested last-nested" role="list"> ${artefactList}  </div>
            </li>`;


    });

    return `
        <li>
            <button class="caret artifectNode" tabindex="0" role="button=" >
                <svg alt="chevron arrow" class="caret-disc" width="14" height="14" viewBox="0 0 14 14" fill="currentColor" class="bx--icon qs-list-closed" xmlns="http://www.w3.org/2000/svg">
                    <rect width="14" height="14" fill="white" fill-opacity="0.01" style="mix-blend-mode:multiply"/>
                    <path d="M8 11L3 6.00005L3.7 5.30005L8 9.60005L12.3 5.30005L13 6.00005L8 11Z"/>
                </svg>
                <div>${languageChildName} (${languageChildCount})</div>
            </button>
            <ul style="padding-left:0px" id="artifectlist" class="nested"> 
                <input type="text" placeholder="Search with file name ..." aria-label="search artifects" role="input"  name="searchArticfects" id="searchArticfects" data-language="${languageChildName}" class="bx--text-input" autocomplete="off"/>
                <button role="button" id="clearInputFilterBtnDiscovery" aria-label="Clear input" tabindex="0" class="bx--tag__close-icon search-clear-icon" data-language="${languageChildName}" value="" aria-label="Clear">
                    <svg alt="close icon" class="bx--tag__close-icon-svg" width="16" height="16" viewBox="0 0 10 10" fill-rule="evenodd">
                    <path d="M9 8.5l-3-3 3-3-.5-.5-3 3-3-3-.5.5 3 3-3 3 .5.5 3-3 3 3z"></path>
                    </svg>
                </button>
                ${fileChildList} 
            </ul>
        </li>`;
}

function buildArtefactList(cryptoInfo, languageChildName, fileChildName, fileChildFullName, fileChildId) {
    return cryptoInfo.map(artefactResults => {
        const artefactName = artefactResults?.title || '';
        const uniqueId = `${artefactName}_*${artefactResults?.crypto_properties?.primitive || ''}_*${artefactResults?.crypto_properties?.cryptoFunction || ''}_*${artefactResults?.call_line || 0}_*${artefactResults?.start || 0}_*${artefactResults?.end || 0}`;

        return `
            <button tabindex="0" style="padding-left:48px;" id="artefactTitle.${artefactName}" class="artefact-title-button artefact-title clickable" data-uaid="${uniqueId}" data-file-type="${languageChildName}" data-file="${fileChildName}" data-file-path="${fileChildFullName}" data-fileid="${fileChildId}" data-artefact="${artefactName}" role="button" aria-label="${artefactName}">${artefactName}</button>`;
    }).join('');
}

function toggleVisibilityBasedOnResults(results) {
    const metaWrapper = document.querySelector(".meta-wrapper");
    const treeWrapper = document.getElementById("treeWrapper");
    const noCryptoArtifacts = document.getElementById("noCryptoArtifacts");

    if (results?.length) { // Showing Chart Container and Icons
        metaWrapper.classList.remove("hide");
        treeWrapper.classList.remove("hide");
        noCryptoArtifacts.classList.add("hide");
    } else { // Hiding Chart Container and Icons
        noCryptoArtifacts.classList.remove("hide");
        metaWrapper.classList.add("hide");
    }
}

