function toggleStandardGraphContainer(isHide) {
    const graphGrid = document.getElementById('standardChartContainer');
    const assetGrid = document.getElementById('artifactContainer');
    const standardCollapseBtn = document.getElementById('standardCollapseBtn');
    const isGraphPanelToggled = graphGrid.classList.contains('no-charts-discovery');

    if (isHide === "hide") {
        graphGrid.classList.add('hide');
        standardCollapseBtn.classList.add('hide');

        if (!isGraphPanelToggled) {
            assetGrid.classList.add('no-standard-charts');
        }
    } else if (isHide === "visible") {
        graphGrid.classList.remove('hide');
        standardCollapseBtn.classList.remove('hide');

        if (!isGraphPanelToggled) {
            assetGrid.classList.remove('no-standard-charts');
        }
    } else {
        graphGrid.classList.toggle('no-charts-discovery');
        assetGrid.classList.toggle('no-standard-charts');
    }
}

// Flat inventory generator event
async function generateFlatInventory(data, isSorted) {
    if (data) {
        const itemsPerPage = 10;
        const totalPages = Math.ceil(data.length / itemsPerPage);
        resultDataWithoutFilters = data;

        const findingWprElement = document.getElementById('findings-container');
        findingWprElement.classList.remove("show");
        findingWprElement.classList.add("hide");
        findingWprElement.innerHTML = '';

        if (data.length) {
            await generateInventoryTemplate(findingWprElement, isSorted);
            inventoryArtifactsCount = data.length;

            findingWprElement.classList.remove("hide");
            findingWprElement.classList.add("show");

            // Initial render
            await generatePaginationTemplate(data.length);
            await sortingHandler(data);
            await renderTable(data, currentPageGlobal, itemsPerPage, totalPages);

            const filterData = {
                functions: data.map(item => item.functionName),
                libraries: data.map(item => item.library),
                locations: data.map(item => item.fileName)
            };

            await generateFilterDropdownList(filterData);
            await filterEventsHandler(itemsPerPage);
            await paginationEventsHandler();
            return filterData;
        } else {
            findingWprElement.innerHTML = `
                <div class="bx--accordion__heading custom-accordion__heading no-asset-wrapper">
					<p class="bx--accordion__title custom-accordion__title" role="text" aria-label="No Results Found">No Results Found</p>
				</div>
            `;

            findingWprElement.classList.remove("hide");
            findingWprElement.classList.add("show");
        }

        return { functions: [], libraries: [] };
    }
}

// Pagination events handler (i.e. Next and Previous)
async function paginationEventsHandler() {
    // Event listeners for pagination buttons
    document.getElementById('prev').addEventListener('click', function () {
        if (currentPageGlobal > 1) {
            currentPageGlobal--;
            updateAndRenderTable(currentPageGlobal, itemsPerPageGlobal);
        }
    });

    document.getElementById('next').addEventListener('click', function () {
        if (currentPageGlobal < totalPagesGlobal) {
            currentPageGlobal++;
            updateAndRenderTable(currentPageGlobal, itemsPerPageGlobal);
        }
    });
}

// Function to render the table rows for the current page
async function renderTable(data, currentPage, itemsPerPage, totalPages) {
    itemsPerPageGlobal = itemsPerPage;
    totalPagesGlobal = totalPages;
    currentPageGlobal = currentPage;
    const tableBody = document.getElementById('table-body');
    const currentPageText = document.getElementById("current-page");
    const currentItemsText = document.getElementById("current-items");
    const totalPagesText = document.getElementById("total-pages");
    const totalItemsText = document.getElementById("total-items");
    const itemsPerPageDropdown = document.getElementById("itemsPerPage");
    const prevButton = document.getElementById('prev');
    const nextButton = document.getElementById('next');

    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = Math.min(startIndex + itemsPerPage, data.length);
    const dataToRender = data.slice(startIndex, endIndex);

    // Clear existing rows
    tableBody.innerHTML = '';

    // Add new rows to the table
    dataToRender.forEach(item => {
        const lineNumberString = JSON.stringify(item);

        const row = `
            <tr class="clickable" data-line='${lineNumberString}'>
                <td class="medium">${item.functionName || '-'}</td>
                <td class="small">${item.library || '-'}</td>
                <td class="large" data-location="${item.fileName}">${item.location}</td>
            </tr>`;
        tableBody.insertAdjacentHTML('beforeend', row);
    });

    if (!dataToRender.length) {
        tableBody.insertAdjacentHTML('beforeend', `
            <tr><td colspan="3">No results found.</td></tr>`);
    }

    let pagesDropdownList = '';
    for (let i = 0; i < totalPages; i++) {
        pagesDropdownList += `<option class="bx--select-option" value="${i + 1}">${i + 1}</option>`;
    }
    currentPageText.innerHTML = pagesDropdownList;

    // Update page number
    currentPageText.value = currentPage;
    totalPagesText.textContent = totalPages;
    totalItemsText.textContent = data.length;

    // Enable/Disable prev and next buttons
    prevButton.disabled = currentPage === 1;
    nextButton.disabled = currentPage === totalPages;

    function calculateItemsOnPage(itemsPerPage, totalItems, currentPage) {
        let startIndex = (currentPage - 1) * itemsPerPage + 1;
        let endIndex = Math.min(currentPage * itemsPerPage, totalItems);

        return `${startIndex}-${endIndex}`;
    }

    currentItemsText.textContent = calculateItemsOnPage(itemsPerPage, data.length, currentPage);
    itemsPerPageDropdown.value = itemsPerPage;

    handleTableHeight();
}

