// Sorting Handler
async function sortingHandler(data) {
    const buttons = document.querySelectorAll('.sort-inventory');
    buttons.forEach(button => {
        button.addEventListener('click', async (e) => {
            e.target.closest('svg').classList.toggle('sorted');
            const addSortedClass = !!(e.target.closest('svg').classList.contains('sorted'));

            const sortingType = addSortedClass ? "ascending" : "descending";
            updateAndRenderTable(1, itemsPerPageGlobal, true, sortingType);
        });
    });
}

// Filter Handler
async function filterTable(fullResultData, selectedData, currentPage, itemsPerPage, isSorted, sortingType) {

    const filteredData = await Promise.all(fullResultData.map(async item => {
        const cells = {
            functions: item.functionName,
            libraries: item.library,
            locations: item.fileName
        };

        const [isFunctionMatched, isLibraryMatched, isLocationMatched] = await Promise.all([
            isFilterMatching("functions", selectedData, cells),
            isFilterMatching("libraries", selectedData, cells),
            isFilterMatching("locations", selectedData, cells)
        ]);

        if (isFunctionMatched && isLibraryMatched && isLocationMatched) {
            return item;
        }
        return null;
    }));

    const result = filteredData.filter(item => item !== null);
    const totalPages = Math.ceil(result.length / itemsPerPage) || 1;

    if (currentPage > totalPages) {
        currentPage = 1;
    }

    if (isSorted) {
        sortingType === "ascending" ? await sortAscendingInventoryList(result) : await sortDescendingInventoryList(result);
    }

    await updateAndGenerateGraphs(result);
    await renderTable(result, currentPage, itemsPerPage, totalPages);
}

// Function to check if selected filter and row cell matching
async function isFilterMatching(columnType, selectedData, cells) {
    const selectedFilter = [...new Set(selectedData[columnType])];
    return selectedFilter.length ? selectedFilter.includes(cells[columnType]) : true;
}

// Filter Events Handler
async function filterEventsHandler(itemsPerPage) {
    const filterInput = document.querySelectorAll(".inventory-filter-input");

    filterInput.forEach(input => {
        const optionsList = input.nextElementSibling.querySelector(".bx--multi-select__menu-list");
        const menu = optionsList.parentElement;

        input.addEventListener('input', function () {
            const filterText = input.value.toLowerCase();
            const items = optionsList.querySelectorAll(".bx--multi-select__menu-item");

            items.forEach(item => {
                const label = item.querySelector("label").textContent.toLowerCase();
                if (label.includes(filterText)) {
                    item.style.display = "flex";
                } else {
                    item.style.display = "none";
                }
            });
        });

        input.addEventListener("click", function () {
            const parentElm = input.parentElement;
            parentElm.querySelector('.search-icon').classList.add("tag-search");
            menu.classList.add("show");
        });

        optionsList.addEventListener("change", async function (event) {
            if (event.target.type === "checkbox") {
                event.target.setAttribute("aria-selected", event.target.checked);
                const selectedOptions = await updateAndRenderTable(1, itemsPerPage);
                await displaySelectedFilterTags(selectedOptions);
            }
        });
    });

    document.addEventListener("click", function (event) {
        const functionInput = document.getElementById("function-filter");
        const libraryInput = document.getElementById("library-filter");
        const locationInput = document.getElementById("location-filter");
        const functionFilterList = document.getElementById("functions-filter-list");
        const libraryFilterList = document.getElementById("libraries-filter-list");
        const locationFilterList = document.getElementById("locations-filter-list");

        if (functionFilterList && !functionFilterList.contains(event.target) && event.target !== functionInput) {
            closeDropdownList({ list: functionFilterList, input: functionInput });
        }
        if (libraryFilterList && !libraryFilterList.contains(event.target) && event.target !== libraryInput) {
            closeDropdownList({ list: libraryFilterList, input: libraryInput });
        }
        if (locationFilterList && !locationFilterList.contains(event.target) && event.target !== locationInput) {
            closeDropdownList({ list: locationFilterList, input: locationInput });
        }
    });
}

// Close dropdown list for filters
