// Table Height Handler
function handleTableHeight() {
    const container = document.getElementById('tab-content-2');
    const tableBody = document.getElementById('table-body');

    const threshold = 250;
    function checkTableOverflow() {
        const tableHeight = tableBody.offsetHeight;
        if (tableHeight > threshold) {
            container.style.overflow = 'auto';
        } else {
            container.style.overflowY = 'visible';
        }
    }

    requestAnimationFrame(() => {
        checkTableOverflow();
    });
}

// Function to update the data and render table with updated data
async function updateAndRenderTable(modifiedCurrentPage, itemPerPage, isSorted = false, sortingType = "ascending") {
    let selectedOptions = {
        functions: [],
        libraries: [],
        locations: []
    };

    document.querySelectorAll(".bx--multi-select__menu-list").forEach(list => {
        const checkboxes = list.querySelectorAll('input[type="checkbox"]:checked');
        selectedOptions[list.dataset.item] = [...checkboxes].map(checkbox => checkbox.value);
    });

    await filterTable(resultDataWithoutFilters, selectedOptions, modifiedCurrentPage, itemPerPage, isSorted, sortingType);
    return selectedOptions;
}

// Function to handle pagination event changes (i.e. current page changes, items per page changes)
function handleChangePagination(e) {
    const itemPerPageValue = document.getElementById("itemsPerPage");
    const currentPageValue = document.getElementById("current-page");
    updateAndRenderTable(Number(currentPageValue.value), Number(itemPerPageValue.value));
}

// Function to handler graph updates after pagination
async function updateAndGenerateGraphs(results) {
    const { functionsData, librariesData } = {
        functionsData: results.map(item => item.functionName),
        librariesData: results.map(item => item.library)
    };
    const instances = generateJavaGraphData(functionsData || []);
    const libraries = generateJavaGraphData(librariesData || []);

    toggleStandardGraphContainer("visible");
    await generateGraph({ instances, libraries });
}