// Polyfill for __dirname in browsers or vanilla JS environments
if (typeof __dirname === 'undefined') {
  const currentScript = document.currentScript;
  if (currentScript) {
    const scriptUrl = currentScript.src;
    window.__dirname = scriptUrl.substring(0, scriptUrl.lastIndexOf('/'));
  } else {
    window.__dirname = window.location.href.substring(0, window.location.href.lastIndexOf('/'));
  }
}
