export async function generateFiltersData(cryptoData) {
    const complianceIcon = getQuantumSafeStatus();
    let fipsGraphData = {};

    if (cryptoData?.assets?.[0]?.complianceLevels) {
        cryptoData?.assets?.forEach(a => {
            if (!a?.complianceLevels?.length) {
                fipsGraphData['notApplicable'] = (fipsGraphData['notApplicable'] || 0) + 1;
            } else {
                a.complianceLevels
                    .filter(item => item.type === ComplianceStatus.fipsType)
                    .forEach(item => {
                        fipsGraphData[_.camelCase(item.label)] = (fipsGraphData[_.camelCase(item.label)] || 0) + 1;
                    });
            }
        });
    }

    let filterData = {
        cryptoFunctions: [],
        vulnerabilities: [],
        cryptoAgile: [],
        quantumSafe: [],
        fipsCompliant: [],
        variants: [],
        publicKeySize: [],
        privateKeySize: [],
        blockSize: [],
        keyVariant: [],
        variantCombination: [],
        libraries: [],
        vulnerabilitiesCount: 0,
        variantCount: 0
    };
    filterData.vulnerabilitiesCount = 0;

    for (let asset of cryptoData?.assets || []) {
        const properties = asset?.cryptoProperties;

        let fipsValue;
        let quantumSafeValue;
        let cryptoAgileValue;

        const isInvalidFipsCompliance = !asset?.complianceLevels?.length || !asset.complianceLevels.some(item => item.type === ComplianceStatus.fipsType);

        if (isInvalidFipsCompliance) {
            asset.complianceLevels = [...asset.complianceLevels, { type: ComplianceStatus.fipsType, label: ComplianceStatus.notApplicable }];
        }

        asset?.complianceLevels?.filter(item => item.type === ComplianceStatus.fipsType).map(item => {
            fipsValue = item.label;
        });

        const isInvalidQuantumCompliance = !asset?.complianceLevels?.length || !asset.complianceLevels.some(item => item.type === ComplianceStatus.quantumSafeType);

        if (isInvalidQuantumCompliance) {
            asset.complianceLevels = [...asset.complianceLevels, { type: ComplianceStatus.quantumSafeType, label: ComplianceStatus.notApplicable }];
        }

        asset?.complianceLevels?.filter(item => item.type === ComplianceStatus.quantumSafeType).map(item => {
            quantumSafeValue = complianceIcon[_.camelCase(item?.label)].text;
        });

        cryptoAgileValue = asset?.vulnerabilities.length === 0 ? ComplianceStatus.agile : ComplianceStatus.notAgile;

        if (asset.vulnerabilities) {
            filterData.vulnerabilitiesCount += asset.vulnerabilities.length;
            filterData.vulnerabilities.push(...asset.vulnerabilities);
        }

        function pushIfDefined(array, value, extraProperties = {}) {
            if (value !== undefined) {
                array.push({ value, checked: false, ...extraProperties });
                filtersLength++;
            }
        }

        pushIfDefined(filterData.cryptoFunctions, properties?.cryptoFunction);
        pushIfDefined(filterData.fipsCompliant, fipsValue);
        pushIfDefined(filterData.quantumSafe, quantumSafeValue);
        pushIfDefined(filterData.cryptoAgile, cryptoAgileValue);
        pushIfDefined(filterData.variants, properties?.variant);
        pushIfDefined(filterData.publicKeySize, properties?.publicKeySize);
        pushIfDefined(filterData.privateKeySize, properties?.privateKeySize, {
            keyVariant: `${properties?.variant || 'Unknown'}-${properties?.privateKeySize || 'Unknown'}`
        });
        pushIfDefined(filterData.blockSize, properties?.blockSize);
        if (properties?.variant) {
            filterData.variantCombination.push({ algorithm: properties.variant, key: properties?.privateKeySize || 'Unknown' });
        }
    }

    let graphData = {
        vulnerabilitiesCount: filterData.vulnerabilitiesCount,
        variantCount: [...new Set(filterData.variants)].length,
        algorithmData: groupBy(filterData.variants, 'value'),
        vulnerabilityData: groupBy(filterData.vulnerabilities, 'vulnerabilityScore'),
        keyData: groupBy(filterData.keyVariant, 'value')
    };
    await saveData(graphData?.vulnerabilitiesCount, 'vulnerabilitiesCount');
    await saveData(graphData.variantCount, 'variantsCount');

    graphData.vulnerabilityLabels = graphData.vulnerabilityData.map(a => a.label);
    graphData.vulnerabilityValues = graphData.vulnerabilityData.map(a => a.value);
    graphData.keyLabels = graphData.keyData.map(a => a.label);
    graphData.keyValues = graphData.keyData.map(a => a.value);
    graphData.algorithmGraphData = filterData.variantCombination;
    graphData.fipsLevels = Object.keys(fipsGraphData);
    graphData.fipsValues = Object.values(fipsGraphData);
    graphData.fipsData = Object.entries(fipsGraphData).map(([label, value], index) => ({ label, value, index }));

    async function setFilterData(data, dataType) {
        const uniqueData = [...new Map(data.map(item => [dataType === 'VUL' ? item.vulnerabilityScore : item.value, item])).values()];
        return uniqueData;
    }

    return {
        cryptoFunction: await setFilterData(filterData.cryptoFunctions, 'V'),
        vulnerabilities: await setFilterData(filterData.vulnerabilities, 'VUL'),
        cryptoAgile: await setFilterData(filterData.cryptoAgile, 'V'),
        fipsCompliant: await setFilterData(filterData.fipsCompliant, 'V'),
        quantumSafe: await setFilterData(filterData.quantumSafe, 'V'),
        variant: await setFilterData(filterData.variants, 'V'),
        publicKeySize: await setFilterData(filterData.publicKeySize, 'V'),
        privateKeySize: await setFilterData(filterData.privateKeySize, 'V'),
        blockSize: await setFilterData(filterData.blockSize, 'V'),
        library: await setFilterData(filterData.libraries, 'V'),
        vulnerabilitiesCount: filterData.vulnerabilitiesCount,
        variantCount: [...new Set(filterData.variants)].length,
        graphData: graphData
    };
}

async function searchFilter(event) {
    const searchInput = event.value.length >= 2 ? event : '';

    await loadFilterTagsTemplate();
    await loadFilterTemplate(searchInput);

    if (event.value.length >= 2) {
        addAllAccordions();
    } else {
        removeAllAccordions();
    }
}

function onChangeFilter(element) {
    filterAssets({
        filterElement: element.dataset.filter,
        value: element.value
    });
}

async function filterAssets(filterData) {
    const filter = await getSavedData('filter');
    const complianceIcon = getQuantumSafeStatus();

    if (filterData.filterInput) {
        document.getElementById('searchInput').value = '';
    } else if (filterData.filterElement === '' && filterData.value === '' && !filterData.filterInput) {
        clearAllFilters(filter);
    } else if (filterData.value !== '' && filterData.filterElement !== '' && filterData.clearFilter) {
        clearFilterValue(filterData.filterElement, filterData.value, filter);
    } else {
        toggleFilterValue(filterData.filterElement, filterData.value, filter);
    }

    const refinedFiltersList = Object.fromEntries(
        Object.entries(filtersList).filter(([key, value]) => value.length > 0)
    );

    const cryptoData = await getSavedData('crypto');

    if (Object.keys(refinedFiltersList).length > 0) {
        const filteredDataByName = cryptoData?.assets.filter(item => {

            const fipsMatch = item?.complianceLevels?.some(fipsComp =>
                refinedFiltersList.fipsCompliant &&
                refinedFiltersList.fipsCompliant.includes(fipsComp.label) &&
                fipsComp.type === ComplianceStatus.fipsType
            );

            // Quantum Safe Match: true if any complianceLevel matches quantumSafe criteria
            const quantumSafeMatch = item?.complianceLevels?.some(fipsComp =>
                refinedFiltersList.quantumSafe &&
                refinedFiltersList.quantumSafe.includes(complianceIcon[_.camelCase(fipsComp?.label)]?.text) &&
                fipsComp.type === ComplianceStatus.quantumSafeType
            );
            const cryptoAgileMatch = refinedFiltersList?.cryptoAgile
                ? refinedFiltersList?.cryptoAgile.some(itemCryptoAgile => {
                    const isAntiPatternCount = item.vulnerabilities.filter(vul => vul.classification === 'Crypto-agility Anti-pattern')?.length || 0;
                    if (itemCryptoAgile === ComplianceStatus.notAgile) {
                        return isAntiPatternCount > 0;
                    }
                    else if (itemCryptoAgile === ComplianceStatus.agile) {
                        return isAntiPatternCount === 0;
                    } else {
                        return false;
                    }
                })
                : false;

            return Object.keys(refinedFiltersList).every(key => {
                if (key === 'fipsCompliant') {
                    return fipsMatch;
                }
                if (key === 'quantumSafe') {
                    return quantumSafeMatch;
                }
                if (key === 'cryptoAgile') {
                    return cryptoAgileMatch;
                }
                return refinedFiltersList[key].includes(item.cryptoProperties[key]);

            });
        });

        fullFilterData = { fileType: '', assets: filteredDataByName };
        await saveData(fullFilterData?.assets, 'filteredData');
    } else {
        fullFilterData = cryptoData;
    }

    if (!filterData.filterInput) {
        destroyGraphs();
        const filterData = await generateFiltersData(fullFilterData);
        await generateGraphs(filterData.graphData);

        const itemsPerPage = 10;
        const totalPages = Math.ceil(fullFilterData?.assets?.length / itemsPerPage);
        await renderList('filter', fullFilterData?.assets, 1, itemsPerAssetPageGlobal, totalPages);

        loadFilterCountTemplate();
    }

    loadFilterTagsTemplate();

    if (filterData.filterElement === '' && filterData.value === '') {
        loadFilterTemplate('');
    }

    loadFilterInputTemplate();
}

function clearAllFilters(filter) {
    document.getElementById('searchInput').value = '';
    Object.keys(filtersList).forEach(fltrKey => {
        filtersList[fltrKey] = [];
        filter[fltrKey].forEach(filterObj => filterObj.checked = false);
    });
}

function clearFilterValue(filterElement, value, filter) {
    for (let filterObj of filter[filterElement]) {
        if (filterObj.value === value) {
            filterObj.checked = false;
            break;
        }
    }
    const index = filtersList[filterElement].indexOf(value);
    if (index !== -1) {
        filtersList[filterElement].splice(index, 1);
    }
}

function toggleFilterValue(filterElement, value, filter) {
    if (filtersList[filterElement]?.includes(value)) {
        const index = filtersList[filterElement].indexOf(value);
        if (index !== -1) {
            filtersList[filterElement].splice(index, 1);
        }
        filter[filterElement].forEach(filterObj => {
            if (filterObj.value === value) {
                filterObj.checked = false;
            }
        });
    } else {
        filtersList[filterElement].push(value);
        filter[filterElement].forEach(filterObj => {
            if (filterObj.value === value) {
                filterObj.checked = true;
            }
        });
    }
}

function destroyGraphs() {
    if (vulnerabilitiesGraph) {
        vulnerabilitiesGraph.destroy();
    }
    if (algorithmsGraph) {
        algorithmsGraph.destroy();
    }
}

function toggleFilterAccordionContent(accordionItem) {
    const dataSet = accordionItem.dataset;
    const content = accordionItem.nextElementSibling;
    const svg = accordionItem.querySelector('.filter_arrow_icon');
    svg.classList.toggle('arrow-rotate');
    content.classList.toggle('filter-accordion__content--hidden');

    ANALYSIS_FILTER_SECTIONS.forEach(section => {
        if (section?.key === dataSet?.key) {
            section.isExpanded = dataSet?.expanded === 'false' ? true : false;
        }
    });
}

export function removeAllAccordions() {
    const items = document.querySelectorAll("#filterAccordion .filter-accordion__item");
    const addAccordionElm = document.getElementById('addAllAccordian');
    const removeAccordionElm = document.getElementById("removeAllAccordian");

    items.forEach(item => {
        const content = item.querySelector(".filter-accordion__content");
        const arrow = item.querySelector(".filter_arrow_icon");

        if (content) {
            content.classList.add("filter-accordion__content--hidden");
        }
        if (arrow) {
            arrow.classList.add("arrow-rotate");
        }
    });

    if (addAccordionElm) {
        addAccordionElm.style.display = "block";
    }

    if (removeAccordionElm) {
        removeAccordionElm.style.display = "none";
    }

    ANALYSIS_FILTER_SECTIONS.forEach(section => {
        section.isExpanded = false;
    });
}

function addAllAccordions() {
    const items = document.querySelectorAll("#filterAccordion .filter-accordion__item");

    items.forEach(item => {
        const content = item.querySelector(".filter-accordion__content");
        const arrow = item.querySelector(".filter_arrow_icon");

        if (content) {
            content.classList.remove("filter-accordion__content--hidden");
        }
        if (arrow) {
            arrow.classList.remove("arrow-rotate");
        }
    });
    document.getElementById('addAllAccordian').style.display = "none";
    document.getElementById("removeAllAccordian").style.display = "block";
    ANALYSIS_FILTER_SECTIONS.forEach(section => {
        section.isExpanded = true;
    });
}

function toggleFilterContainer() {
    const filterGrid = document.getElementById('filterGrid');
    const assetGrid = document.getElementById('assetGrid');
    filterGrid.classList.toggle('hide');
    if (assetGrid.classList.contains('asset-container')) {
        assetGrid.classList.remove('asset-container');
        assetGrid.classList.add('asset-min-container');
        assetGrid.classList.add('assetGrid');
        document.getElementById("searchInput").focus();
    }
    else if (assetGrid.classList.contains('asset-min-container')) {
        assetGrid.classList.remove('asset-min-container');
        assetGrid.classList.remove('assetGrid');
        assetGrid.classList.add('asset-container');
    }
}

function toggleGraphContainer() {
    const graphGrid = document.getElementById('chartContainer');
    const assetGrid = document.getElementById('assetContainer');
    graphGrid.classList.toggle('hide');
    assetGrid.classList.toggle('no-charts');
}

function changeFilterPress(event, element) {
    if (event.keyCode === 13) {
        event.preventDefault();
        onChangeFilter(element);
    }
}

